#property copyright "Copyright 2024, MetaQuotes Ltd."
#property link      "https://www.mql5.com"
#property version   "1.00"
#property indicator_chart_window // O indicador desenha no gráfico principal

//--- Parâmetros de Entrada
input color  InpBullColor = clrLightBlue; // Cor do FVG de Alta (Bullish)
input color  InpBearColor = clrLightPink; // Cor do FVG de Baixa (Bearish)
input int    InpTransparency = 120;       // Transparência (0-255)
input int    InpLookback = 500;           // Quantidade de velas para analisar
input bool   InpDrawFilled = true;        // Mostrar gaps já preenchidos?

//+------------------------------------------------------------------+
//| Custom indicator initialization function                         |
//+------------------------------------------------------------------+
int OnInit()
{
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Custom indicator deinitialization function                       |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   // Limpa os objetos criados ao remover o indicador
   ObjectsDeleteAll(0, "FVG_");
}

//+------------------------------------------------------------------+
//| Custom indicator iteration function                              |
//+------------------------------------------------------------------+
int OnCalculate(const int rates_total,
                const int prev_calculated,
                const datetime &time[],
                const double &open[],
                const double &high[],
                const double &low[],
                const double &close[],
                const long &tick_volume[],
                const long &volume[],
                const int &spread[])
{
   // Ajustar a série temporal (o índice 0 será a vela mais recente)
   ArraySetAsSeries(high, true);
   ArraySetAsSeries(low, true);
   ArraySetAsSeries(time, true);

   int limit = rates_total - prev_calculated;
   if(limit > InpLookback) limit = InpLookback;

   // Loop para verificar os gaps (começamos do 1 para evitar erro de índice)
   for(int i = 1; i < limit; i++)
   {
      // A lógica do FVG baseia-se em 3 velas:
      // Vela 1 (Anterior), Vela 2 (A que deixa o gap), Vela 3 (Posterior)
      // No código: i+1 (Vela 1), i (Vela 2), i-1 (Vela 3)

      string objName = "";

      // --- BULLISH FVG (Gap de Alta)
      // Máximo da Vela 1 é menor que o Mínimo da Vela 3
      if(high[i+1] < low[i-1])
      {
         objName = "FVG_Bull_" + TimeToString(time[i]);
         CreateBox(objName, time[i+1], high[i+1], time[i-1], low[i-1], InpBullColor);
      }

      // --- BEARISH FVG (Gap de Baixa)
      // Mínimo da Vela 1 é maior que o Máximo da Vela 3
      if(low[i+1] > high[i-1])
      {
         objName = "FVG_Bear_" + TimeToString(time[i]);
         CreateBox(objName, time[i+1], low[i+1], time[i-1], high[i-1], InpBearColor);
      }
   }

   return(rates_total);
}

//+------------------------------------------------------------------+
//| Função auxiliar para criar as caixas (Retângulos)                |
//+------------------------------------------------------------------+
void CreateBox(string name, datetime t1, double p1, datetime t2, double p2, color clr)
{
   if(ObjectFind(0, name) < 0)
   {
      ObjectCreate(0, name, OBJ_RECTANGLE, 0, t1, p1, t2, p2);
      ObjectSetInteger(0, name, OBJPROP_COLOR, clr);
      ObjectSetInteger(0, name, OBJPROP_FILL, true);
      ObjectSetInteger(0, name, OBJPROP_BACK, true); // Fica atrás das velas
      ObjectSetInteger(0, name, OBJPROP_WIDTH, 1);

      // Adiciona transparência se for suportado pela cor
      ObjectSetInteger(0, name, OBJPROP_COLOR, clr);
   }
}

