import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Candle {
  time: number;
  open: number;
  high: number;
  low: number;
  close: number;
}

export enum FVGType {
  BULLISH = 'BULLISH',
  BEARISH = 'BEARISH'
}

export interface FVGZone {
  id: string;
  type: FVGType;
  top: number;
  bottom: number;
  startTime: number;
  endTime: number;
  mitigated: boolean;
  mitigationTime?: number;
}

export interface IndicatorConfig {
  bullColor: string;
  bearColor: string;
  transparency: number; // 0-255
  lookback: number;
  drawFilled: boolean;
  mitigationDetection: boolean;
}

import { Candle } from '../types';

export const generateMockCandles = (count: number): Candle[] => {
  const candles: Candle[] = [];
  let currentPrice = 50000;
  let currentTime = Math.floor(Date.now() / 1000) - count * 3600;

  for (let i = 0; i < count; i++) {
    const volatility = currentPrice * 0.005;
    const open = currentPrice;
    const close = currentPrice + (Math.random() - 0.5) * volatility;
    const high = Math.max(open, close) + Math.random() * volatility * 0.5;
    const low = Math.min(open, close) - Math.random() * volatility * 0.5;

    candles.push({
      time: currentTime,
      open,
      high,
      low,
      close,
    });

    currentPrice = close;
    currentTime += 3600; // 1h intervals
  }

  return candles;
};

// Add some intentional FVGs to the data
export const injectFVGs = (candles: Candle[]): Candle[] => {
  const newCandles = [...candles];
  for (let i = 2; i < newCandles.length - 2; i += 15) {
    // Inject Bullish FVG
    const bullStrength = 200;
    newCandles[i].close = newCandles[i].open + bullStrength;
    newCandles[i].high = newCandles[i].close + 20;
    newCandles[i].low = newCandles[i].open - 20;

    // Gap candle (candle 2)
    newCandles[i+1].open = newCandles[i].close;
    newCandles[i+1].close = newCandles[i+1].open + bullStrength * 2;
    newCandles[i+1].high = newCandles[i+1].close + 10;
    newCandles[i+1].low = newCandles[i+1].open - 10;

    // Next candle (candle 3)
    newCandles[i+2].open = newCandles[i+1].close;
    newCandles[i+2].low = newCandles[i+2].open - 20; // Keep it high to leave a gap with candle 1 high
  }
  return newCandles;
};

import { Candle, FVGType, FVGZone, IndicatorConfig } from '../types';

export const detectFVGs = (candles: Candle[], config: IndicatorConfig): FVGZone[] => {
  const zones: FVGZone[] = [];
  const { lookback, mitigationDetection } = config;

  // We need at least 3 candles to detect an FVG
  const startIdx = Math.max(1, candles.length - lookback);

  for (let i = startIdx; i < candles.length - 1; i++) {
    // The logic: 3 candles
    // c1 (previous), c2 (current/gap), c3 (next)
    const c1 = candles[i - 1];
    const c2 = candles[i];
    const c3 = candles[i + 1];

    if (!c1 || !c2 || !c3) continue;

    // --- BULLISH FVG ---
    // High of candle 1 < Low of candle 3
    if (c1.high < c3.low) {
      const zone: FVGZone = {
        id: `bull-${c2.time}`,
        type: FVGType.BULLISH,
        top: c3.low,
        bottom: c1.high,
        startTime: c1.time,
        endTime: c3.time,
        mitigated: false
      };

      // Mitigation check
      if (mitigationDetection) {
        for (let j = i + 2; j < candles.length; j++) {
          if (candles[j].low <= zone.bottom) {
            zone.mitigated = true;
            zone.mitigationTime = candles[j].time;
            break;
          }
        }
      }

      if (config.drawFilled || !zone.mitigated) {
        zones.push(zone);
      }
    }

    // --- BEARISH FVG ---
    // Low of candle 1 > High of candle 3
    if (c1.low > c3.high) {
      const zone: FVGZone = {
        id: `bear-${c2.time}`,
        type: FVGType.BEARISH,
        top: c1.low,
        bottom: c3.high,
        startTime: c1.time,
        endTime: c3.time,
        mitigated: false
      };

      // Mitigation check
      if (mitigationDetection) {
        for (let j = i + 2; j < candles.length; j++) {
          if (candles[j].high >= zone.top) {
            zone.mitigated = true;
            zone.mitigationTime = candles[j].time;
            break;
          }
        }
      }

      if (config.drawFilled || !zone.mitigated) {
        zones.push(zone);
      }
    }
  }

  return zones;
};

import { GoogleGenAI } from "@google/genai";
import { Candle, FVGZone } from "../types";

export const analyzeMarket = async (candles: Candle[], zones: FVGZone[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const currentPrice = candles[candles.length - 1].close;
  const bullishCount = zones.filter(z => z.type === 'BULLISH' && !z.mitigated).length;
  const bearishCount = zones.filter(z => z.type === 'BEARISH' && !z.mitigated).length;

  const prompt = `
    Como um especialista em Smart Money Concepts (SMC), analise os seguintes dados do mercado:
    - Preço Atual: ${currentPrice}
    - Fair Value Gaps de Alta (Não mitigados): ${bullishCount}
    - Fair Value Gaps de Baixa (Não mitigados): ${bearishCount}

    Por favor, forneça uma análise curta e profissional em Português sobre o que esses desequilíbrios (FVGs) sugerem para a direção do preço a curto prazo.
    Mencione se o preço está sendo atraído para preencher algum gap específico.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar uma análise no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com a IA para análise de mercado.";
  }
};

import React, { useMemo, useRef, useState, useEffect } from 'react';
import { Candle, FVGZone, IndicatorConfig, FVGType } from '../types';

interface Props {
  candles: Candle[];
  zones: FVGZone[];
  config: IndicatorConfig;
}

const TradingChart: React.FC<Props> = ({ candles, zones, config }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [size, setSize] = useState({ width: 800, height: 500 });

  useEffect(() => {
    const updateSize = () => {
      if (containerRef.current) {
        setSize({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight
        });
      }
    };
    window.addEventListener('resize', updateSize);
    updateSize();
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const { width, height } = size;
  const padding = { top: 40, right: 60, bottom: 40, left: 20 };

  const chartArea = {
    width: width - padding.left - padding.right,
    height: height - padding.top - padding.bottom
  };

  const candleMetrics = useMemo(() => {
    if (candles.length === 0) return null;
    const highs = candles.map(c => c.high);
    const lows = candles.map(c => c.low);
    const minPrice = Math.min(...lows) * 0.999;
    const maxPrice = Math.max(...highs) * 1.001;
    const priceRange = maxPrice - minPrice;

    const candleWidth = chartArea.width / candles.length;

    const getY = (price: number) => 
      padding.top + chartArea.height - ((price - minPrice) / priceRange) * chartArea.height;

    const getX = (index: number) => 
      padding.left + index * candleWidth + candleWidth / 2;

    return { getY, getX, candleWidth, minPrice, maxPrice, priceRange };
  }, [candles, chartArea, padding]);

  if (!candleMetrics) return <div className="flex items-center justify-center h-full text-gray-500">Aguardando dados...</div>;

  const { getY, getX, candleWidth } = candleMetrics;

  return (
    <div ref={containerRef} className="w-full h-full relative bg-slate-900 rounded-xl overflow-hidden shadow-2xl border border-slate-800">
      <svg width={width} height={height} className="select-none cursor-crosshair">
        {/* Grid Lines */}
        {[0, 0.25, 0.5, 0.75, 1].map(p => {
          const price = candleMetrics.minPrice + p * candleMetrics.priceRange;
          const y = getY(price);
          return (
            <g key={p}>
              <line x1={padding.left} y1={y} x2={width - padding.right} y2={y} stroke="#1e293b" strokeDasharray="4 4" />
              <text x={width - padding.right + 5} y={y + 4} fill="#64748b" fontSize="10">{price.toFixed(2)}</text>
            </g>
          );
        })}

        {/* FVG Zones */}
        {zones.map(zone => {
          const startIdx = candles.findIndex(c => c.time === zone.startTime);
          const endIdx = zone.mitigated && zone.mitigationTime 
            ? candles.findIndex(c => c.time === zone.mitigationTime)
            : candles.length - 1;

          if (startIdx === -1) return null;

          const x1 = getX(startIdx) - candleWidth / 2;
          const x2 = getX(endIdx) + candleWidth / 2;
          const yTop = getY(zone.top);
          const yBottom = getY(zone.bottom);

          const color = zone.type === FVGType.BULLISH ? config.bullColor : config.bearColor;
          const opacity = config.transparency / 255;

          return (
            <rect
              key={zone.id}
              x={x1}
              y={Math.min(yTop, yBottom)}
              width={Math.max(0, x2 - x1)}
              height={Math.abs(yTop - yBottom)}
              fill={color}
              fillOpacity={opacity}
              stroke={color}
              strokeOpacity={opacity + 0.2}
              strokeWidth="1"
            />
          );
        })}

        {/* Candlesticks */}
        {candles.map((candle, i) => {
          const x = getX(i);
          const bodyTop = getY(Math.max(candle.open, candle.close));
          const bodyBottom = getY(Math.min(candle.open, candle.close));
          const wickTop = getY(candle.high);
          const wickBottom = getY(candle.low);
          const isBull = candle.close >= candle.open;
          const color = isBull ? '#10b981' : '#ef4444';

          return (
            <g key={candle.time}>
              <line x1={x} y1={wickTop} x2={x} y2={wickBottom} stroke={color} strokeWidth="1" />
              <rect
                x={x - (candleWidth * 0.8) / 2}
                y={bodyTop}
                width={candleWidth * 0.8}
                height={Math.max(1, bodyBottom - bodyTop)}
                fill={color}
                opacity={0.9}
              />
            </g>
          );
        })}
      </svg>
    </div>
  );
};

export default TradingChart;

import React, { useState, useEffect, useCallback } from 'react';
import { Candle, FVGZone, IndicatorConfig, FVGType } from './types';
import { generateMockCandles, injectFVGs } from './utils/mockDataGenerator';
import { detectFVGs } from './utils/fvgDetector';
import { analyzeMarket } from './services/geminiService';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [candles, setCandles] = useState<Candle[]>([]);
  const [zones, setZones] = useState<FVGZone[]>([]);
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [activeTab, setActiveTab] = useState<'chart' | 'settings'>('chart');

  const [config, setConfig] = useState<IndicatorConfig>({
    bullColor: '#3b82f6',
    bearColor: '#ec4899',
    transparency: 100,
    lookback: 500,
    drawFilled: true,
    mitigationDetection: true
  });

  // Initialization
  useEffect(() => {
    const baseCandles = generateMockCandles(100);
    const enrichedCandles = injectFVGs(baseCandles);
    setCandles(enrichedCandles);
  }, []);

  // Update zones whenever candles or config changes
  useEffect(() => {
    if (candles.length > 0) {
      const newZones = detectFVGs(candles, config);
      setZones(newZones);
    }
  }, [candles, config]);

  const handleRunAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, zones);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const refreshData = () => {
    const baseCandles = generateMockCandles(100);
    const enrichedCandles = injectFVGs(baseCandles);
    setCandles(enrichedCandles);
    setAiAnalysis('');
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-950 text-slate-200">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-4 bg-slate-900 border-b border-slate-800 shadow-lg">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-indigo-500/20 shadow-xl">
            <i className="fas fa-chart-line text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight text-white">SMC FVG Indicator</h1>
            <p className="text-xs text-slate-400 uppercase tracking-widest font-semibold">Institutional Zone Mapping</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={refreshData}
            className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-slate-800 hover:bg-slate-700 transition-colors text-sm font-medium border border-slate-700"
          >
            <i className="fas fa-sync-alt"></i>
            Atualizar Dados
          </button>
          <div className="h-6 w-px bg-slate-700"></div>
          <button 
            onClick={handleRunAnalysis}
            disabled={isAnalyzing}
            className="flex items-center gap-2 px-4 py-1.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 transition-all text-sm font-semibold shadow-lg shadow-indigo-500/20"
          >
            {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-robot"></i>}
            Análise IA
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex flex-1 overflow-hidden">
        {/* Left Sidebar - Navigation / Settings */}
        <nav className="w-16 md:w-20 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6">
          <button 
            onClick={() => setActiveTab('chart')}
            className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${activeTab === 'chart' ? 'bg-indigo-600 text-white' : 'hover:bg-slate-800 text-slate-500'}`}
          >
            <i className="fas fa-chart-bar text-xl"></i>
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${activeTab === 'settings' ? 'bg-indigo-600 text-white' : 'hover:bg-slate-800 text-slate-500'}`}
          >
            <i className="fas fa-sliders-h text-xl"></i>
          </button>
        </nav>

        {/* Dynamic Panel Area */}
        <div className="flex-1 flex flex-col md:flex-row p-6 gap-6 overflow-hidden">

          {activeTab === 'chart' ? (
            <div className="flex-1 flex flex-col gap-6 overflow-hidden">
              <div className="flex-1 min-h-0">
                <TradingChart candles={candles} zones={zones} config={config} />
              </div>

              {/* Stats Bar */}
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                  <span className="text-xs text-slate-500 uppercase font-bold block mb-1">Total Zones</span>
                  <span className="text-2xl font-bold text-white">{zones.length}</span>
                </div>
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                  <span className="text-xs text-blue-500 uppercase font-bold block mb-1">Bullish Gaps</span>
                  <span className="text-2xl font-bold text-blue-400">{zones.filter(z => z.type === FVGType.BULLISH).length}</span>
                </div>
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                  <span className="text-xs text-pink-500 uppercase font-bold block mb-1">Bearish Gaps</span>
                  <span className="text-2xl font-bold text-pink-400">{zones.filter(z => z.type === FVGType.BEARISH).length}</span>
                </div>
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                  <span className="text-xs text-emerald-500 uppercase font-bold block mb-1">Mitigated</span>
                  <span className="text-2xl font-bold text-emerald-400">{zones.filter(z => z.mitigated).length}</span>
                </div>
              </div>
            </div>
          ) : (
            <div className="flex-1 bg-slate-900 rounded-2xl border border-slate-800 p-8 max-w-2xl mx-auto overflow-y-auto">
              <h2 className="text-2xl font-bold mb-8 flex items-center gap-3">
                <i className="fas fa-cog text-indigo-500"></i> Configurações do Indicador
              </h2>

              <div className="space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Cor Bullish FVG</label>
                    <input 
                      type="color" 
                      value={config.bullColor} 
                      onChange={(e) => setConfig(prev => ({ ...prev, bullColor: e.target.value }))}
                      className="w-full h-12 rounded-lg bg-slate-800 border border-slate-700 cursor-pointer p-1"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Cor Bearish FVG</label>
                    <input 
                      type="color" 
                      value={config.bearColor} 
                      onChange={(e) => setConfig(prev => ({ ...prev, bearColor: e.target.value }))}
                      className="w-full h-12 rounded-lg bg-slate-800 border border-slate-700 cursor-pointer p-1"
                    />
                  </div>
                </div>

                <div>
                  <label className="flex justify-between text-sm font-medium text-slate-400 mb-2">
                    Transparência <span>{Math.round((config.transparency / 255) * 100)}%</span>
                  </label>
                  <input 
                    type="range" min="0" max="255" value={config.transparency} 
                    onChange={(e) => setConfig(prev => ({ ...prev, transparency: parseInt(e.target.value) }))}
                    className="w-full accent-indigo-500"
                  />
                </div>

                <div>
                  <label className="flex justify-between text-sm font-medium text-slate-400 mb-2">
                    Lookback (Velas) <span>{config.lookback}</span>
                  </label>
                  <input 
                    type="range" min="50" max="1000" step="50" value={config.lookback} 
                    onChange={(e) => setConfig(prev => ({ ...prev, lookback: parseInt(e.target.value) }))}
                    className="w-full accent-indigo-500"
                  />
                </div>

                <div className="space-y-4">
                  <label className="flex items-center justify-between p-4 bg-slate-800 rounded-xl cursor-pointer hover:bg-slate-750 transition-colors">
                    <span className="font-medium">Mostrar zonas mitigadas (preenchidas)</span>
                    <input 
                      type="checkbox" checked={config.drawFilled} 
                      onChange={(e) => setConfig(prev => ({ ...prev, drawFilled: e.target.checked }))}
                      className="w-5 h-5 accent-indigo-500"
                    />
                  </label>
                  <label className="flex items-center justify-between p-4 bg-slate-800 rounded-xl cursor-pointer hover:bg-slate-750 transition-colors">
