import { Candle, Asset } from '../types';

export const generateMockCandles = (count: number, asset: Asset): Candle[] => {
  const candles: Candle[] = [];
  let currentPrice = asset.basePrice;
  let currentTime = Math.floor(Date.now() / 1000) - count * 3600;

  for (let i = 0; i < count; i++) {
    const volatility = currentPrice * asset.volatility;
    const open = currentPrice;
    const close = currentPrice + (Math.random() - 0.5) * volatility;
    const high = Math.max(open, close) + Math.random() * volatility * 0.5;
    const low = Math.min(open, close) - Math.random() * volatility * 0.5;

    candles.push({
      time: currentTime,
      open,
      high,
      low,
      close,
    });

    currentPrice = close;
    currentTime += 3600; // 1h intervals
  }

  return candles;
};

// Add some intentional FVGs to the data
export const injectFVGs = (candles: Candle[], asset: Asset): Candle[] => {
  const newCandles = [...candles];
  const bullStrength = asset.basePrice * 0.004;

  for (let i = 2; i < newCandles.length - 2; i += 15) {
    // Inject Bullish FVG
    newCandles[i].close = newCandles[i].open + bullStrength;
    newCandles[i].high = newCandles[i].close + (bullStrength * 0.1);
    newCandles[i].low = newCandles[i].open - (bullStrength * 0.1);

    // Gap candle (candle 2)
    newCandles[i+1].open = newCandles[i].close;
    newCandles[i+1].close = newCandles[i+1].open + bullStrength * 1.5;
    newCandles[i+1].high = newCandles[i+1].close + (bullStrength * 0.05);
    newCandles[i+1].low = newCandles[i+1].open - (bullStrength * 0.05);

    // Next candle (candle 3)
    newCandles[i+2].open = newCandles[i+1].close;
    newCandles[i+2].low = newCandles[i+2].open - (bullStrength * 0.1); // Keep it high to leave a gap with candle 1 high
  }
  return newCandles;
};

import { GoogleGenAI } from "@google/genai";
import { Candle, FVGZone, Asset } from "../types";

export const analyzeMarket = async (candles: Candle[], zones: FVGZone[], asset: Asset): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const currentPrice = candles[candles.length - 1].close;
  const bullishCount = zones.filter(z => z.type === 'BULLISH' && !z.mitigated).length;
  const bearishCount = zones.filter(z => z.type === 'BEARISH' && !z.mitigated).length;

  const prompt = `
    Como um especialista em Smart Money Concepts (SMC), analise os seguintes dados do mercado para o ativo ${asset.name} (${asset.symbol}):
    - Preço Atual: ${currentPrice.toFixed(asset.basePrice < 10 ? 4 : 2)}
    - Fair Value Gaps de Alta (Não mitigados): ${bullishCount}
    - Fair Value Gaps de Baixa (Não mitigados): ${bearishCount}

    Por favor, forneça uma análise curta e profissional em Português sobre o que esses desequilíbrios (FVGs) sugerem para a direção do preço do ${asset.symbol} a curto prazo.
    Mencione se o preço está sendo atraído para preencher algum gap específico de ${asset.name}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar uma análise no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com a IA para análise de mercado.";
  }
};

