import { Candle, Asset, Timeframe, TIMEFRAMES } from '../types';

export const generateMockCandles = (count: number, asset: Asset, timeframe: Timeframe): Candle[] => {
  const candles: Candle[] = [];
  let currentPrice = asset.basePrice;
  const timeframeData = TIMEFRAMES.find(t => t.value === timeframe) || TIMEFRAMES[3];
  let currentTime = Math.floor(Date.now() / 1000) - count * timeframeData.seconds;

  for (let i = 0; i < count; i++) {
    const volatility = currentPrice * asset.volatility;
    const open = currentPrice;
    const close = currentPrice + (Math.random() - 0.5) * volatility;
    const high = Math.max(open, close) + Math.random() * volatility * 0.5;
    const low = Math.min(open, close) - Math.random() * volatility * 0.5;

    candles.push({
      time: currentTime,
      open,
      high,
      low,
      close,
    });

    currentPrice = close;
    currentTime += timeframeData.seconds;
  }

  return candles;
};

export const generateNextTick = (lastCandle: Candle, asset: Asset): Candle => {
  const volatility = lastCandle.close * (asset.volatility * 0.1);
  const change = (Math.random() - 0.5) * volatility;
  const newClose = lastCandle.close + change;

  return {
    ...lastCandle,
    close: newClose,
    high: Math.max(lastCandle.high, newClose),
    low: Math.min(lastCandle.low, newClose),
  };
};

export const injectFVGs = (candles: Candle[], asset: Asset): Candle[] => {
  const newCandles = [...candles];
  const bullStrength = asset.basePrice * 0.004;

  for (let i = 2; i < newCandles.length - 15; i += 20) {
    if (i + 2 >= newCandles.length) break;

    // Inject Bullish FVG
    newCandles[i].close = newCandles[i].open + bullStrength;
    newCandles[i].high = newCandles[i].close + (bullStrength * 0.1);
    newCandles[i].low = newCandles[i].open - (bullStrength * 0.1);

    // Gap candle (candle 2)
    newCandles[i+1].open = newCandles[i].close;
    newCandles[i+1].close = newCandles[i+1].open + bullStrength * 1.5;
    newCandles[i+1].high = newCandles[i+1].close + (bullStrength * 0.05);
    newCandles[i+1].low = newCandles[i+1].open - (bullStrength * 0.05);

    // Next candle (candle 3)
    newCandles[i+2].open = newCandles[i+1].close;
    newCandles[i+2].low = newCandles[i+2].open - (bullStrength * 0.1); 
  }
  return newCandles;
};

import React, { useMemo, useRef, useState, useEffect } from 'react';
import { Candle, FVGZone, IndicatorConfig, FVGType, Asset } from '../types';

interface Props {
  candles: Candle[];
  zones: FVGZone[];
  config: IndicatorConfig;
  asset: Asset;
}

const TradingChart: React.FC<Props> = ({ candles, zones, config, asset }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [size, setSize] = useState({ width: 800, height: 500 });

  // Interactive View State
  const [zoom, setZoom] = useState(1); // 1 is default (show all candles)
  const [panOffset, setPanOffset] = useState(0); // Panning horizontal
  const [isDragging, setIsDragging] = useState(false);
  const [dragStartX, setDragStartX] = useState(0);

  useEffect(() => {
    const updateSize = () => {
      if (containerRef.current) {
        setSize({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight
        });
      }
    };
    window.addEventListener('resize', updateSize);
    updateSize();
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const { width, height } = size;
  const padding = { top: 40, right: 80, bottom: 40, left: 10 };

  const chartArea = {
    width: width - padding.left - padding.right,
    height: height - padding.top - padding.bottom
  };

  // Zoom logic: how many candles to show
  const visibleCandleCount = Math.max(10, Math.floor(candles.length / zoom));

  // Panning logic: which candles are in view
  const lastVisibleIdx = Math.min(candles.length - 1, candles.length - 1 - panOffset);
  const firstVisibleIdx = Math.max(0, lastVisibleIdx - visibleCandleCount);
  const visibleCandles = useMemo(() => candles.slice(firstVisibleIdx, lastVisibleIdx + 1), [candles, firstVisibleIdx, lastVisibleIdx]);

  const candleMetrics = useMemo(() => {
    if (visibleCandles.length === 0) return null;
    const highs = visibleCandles.map(c => c.high);
    const lows = visibleCandles.map(c => c.low);
    const minPrice = Math.min(...lows);
    const maxPrice = Math.max(...highs);
    const priceRange = (maxPrice - minPrice) || 1;

    // Add 10% vertical padding
    const paddedMin = minPrice - priceRange * 0.1;
    const paddedMax = maxPrice + priceRange * 0.1;
    const paddedRange = paddedMax - paddedMin;

    const candleWidth = chartArea.width / visibleCandleCount;

    const getY = (price: number) => 
      padding.top + chartArea.height - ((price - paddedMin) / paddedRange) * chartArea.height;

    const getX = (indexInFullArray: number) => {
      const relativeIdx = indexInFullArray - firstVisibleIdx;
      return padding.left + relativeIdx * candleWidth + candleWidth / 2;
    };

    return { getY, getX, candleWidth, minPrice: paddedMin, maxPrice: paddedMax, priceRange: paddedRange };
  }, [visibleCandles, visibleCandleCount, chartArea, padding, firstVisibleIdx]);

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const zoomSpeed = 0.001;
    const newZoom = Math.max(1, Math.min(10, zoom - e.deltaY * zoomSpeed));
    setZoom(newZoom);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStartX(e.clientX);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !candleMetrics) return;
    const deltaX = e.clientX - dragStartX;
    const candleWidth = candleMetrics.candleWidth;
    const panChange = Math.round(deltaX / candleWidth);

    if (panChange !== 0) {
      setPanOffset(prev => {
        const next = prev + panChange;
        return Math.max(0, Math.min(candles.length - visibleCandleCount, next));
      });
      setDragStartX(e.clientX);
    }
  };

  const handleMouseUp = () => setIsDragging(false);

  if (!candleMetrics) return <div className="flex items-center justify-center h-full text-gray-500 bg-slate-900 rounded-xl">Aguardando dados...</div>;

  const { getY, getX, candleWidth } = candleMetrics;

  return (
    <div 
      ref={containerRef} 
      className="w-full h-full relative bg-slate-900 rounded-xl overflow-hidden shadow-2xl border border-slate-800 touch-none"
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      <svg width={width} height={height} className="select-none cursor-crosshair">
        {/* Grid Lines (Prices) */}
        {[0, 0.2, 0.4, 0.6, 0.8, 1].map(p => {
          const price = candleMetrics.minPrice + p * candleMetrics.priceRange;
          const y = getY(price);
          return (
            <g key={p}>
              <line x1={padding.left} y1={y} x2={width - padding.right} y2={y} stroke="#1e293b" strokeWidth="0.5" strokeDasharray="4 4" />
              <text x={width - padding.right + 8} y={y + 4} fill="#64748b" fontSize="10" fontFamily="monospace">
                {price.toFixed(asset.decimals)}
              </text>
            </g>
          );
        })}

        {/* FVG Zones */}
        {zones.map(zone => {
          const startIdx = candles.findIndex(c => c.time === zone.startTime);
          if (startIdx === -1) return null;

          const endIdx = zone.mitigated && zone.mitigationTime 
            ? candles.findIndex(c => c.time === zone.mitigationTime)
            : candles.length - 1;

          // Only render if within visible range roughly
          if (startIdx > lastVisibleIdx || endIdx < firstVisibleIdx) return null;

          const x1 = getX(startIdx) - candleWidth / 2;
          const x2 = getX(endIdx) + candleWidth / 2;
          const yTop = getY(zone.top);
          const yBottom = getY(zone.bottom);

          const color = zone.type === FVGType.BULLISH ? config.bullColor : config.bearColor;
          const opacity = config.transparency / 255;

          return (
            <rect
              key={zone.id}
              x={Math.max(padding.left, x1)}
              y={Math.min(yTop, yBottom)}
              width={Math.min(chartArea.width, Math.max(0, x2 - x1))}
              height={Math.abs(yTop - yBottom)}
              fill={color}
              fillOpacity={opacity}
              stroke={color}
              strokeOpacity={opacity + 0.2}
              strokeWidth="1"
            />
          );
        })}

        {/* Candlesticks */}
        {visibleCandles.map((candle) => {
          const globalIdx = candles.indexOf(candle);
          const x = getX(globalIdx);
          const bodyTop = getY(Math.max(candle.open, candle.close));
          const bodyBottom = getY(Math.min(candle.open, candle.close));
          const wickTop = getY(candle.high);
          const wickBottom = getY(candle.low);
          const isBull = candle.close >= candle.open;
          const color = isBull ? '#10b981' : '#ef4444';

          return (
            <g key={candle.time}>
              <line x1={x} y1={wickTop} x2={x} y2={wickBottom} stroke={color} strokeWidth="1" />
              <rect
                x={x - (candleWidth * 0.8) / 2}
                y={bodyTop}
                width={Math.max(1, candleWidth * 0.8)}
                height={Math.max(1, bodyBottom - bodyTop)}
                fill={color}
                opacity={0.9}
              />
            </g>
          );
        })}
      </svg>

      {/* Zoom Indicator */}
      <div className="absolute top-4 left-4 bg-slate-800/80 px-2 py-1 rounded text-[10px] text-slate-400 border border-slate-700 pointer-events-none uppercase tracking-tighter">
        Zoom: {zoom.toFixed(1)}x | Pan: {panOffset}
      </div>

      {/* Help Overlay */}
      <div className="absolute bottom-4 left-4 text-[10px] text-slate-500 bg-slate-900/50 px-2 py-1 rounded">
        Scroll para zoom • Arraste para pan
      </div>
    </div>
  );
};

export default TradingChart;

