  const [activeTab, setActiveTab] = useState<'chart' | 'settings'>('chart');
  const [isLive, setIsLive] = useState(true);

  const [config, setConfig] = useState<IndicatorConfig>({
    bullColor: '#3b82f6',
    bearColor: '#ec4899',
    transparency: 100,
    lookback: 500,
    drawFilled: true,
    mitigationDetection: true
  });

  const lastTickTime = useRef(0);

  // Initial data generation
  const refreshData = (asset: Asset = selectedAsset, tf: Timeframe = timeframe) => {
    const baseCandles = generateMockCandles(200, asset, tf);
    const enrichedCandles = injectFVGs(baseCandles, asset);
    setCandles(enrichedCandles);
    setAiAnalysis('');
  };

  useEffect(() => {
    refreshData(selectedAsset, timeframe);
  }, [selectedAsset, timeframe]);

  // Real-time tick simulation
  useEffect(() => {
    if (!isLive || candles.length === 0) return;

    const interval = setInterval(() => {
      setCandles(prev => {
        if (prev.length === 0) return prev;
        const last = prev[prev.length - 1];
        const now = Date.now();
        const timeframeSecs = TIMEFRAMES.find(t => t.value === timeframe)?.seconds || 3600;

        // If timeframe has passed, push new candle
        if (now / 1000 > last.time + timeframeSecs) {
          const newCandle: Candle = {
            time: last.time + timeframeSecs,
            open: last.close,
            high: last.close,
            low: last.close,
            close: last.close,
          };
          return [...prev.slice(1), newCandle];
        } else {
          // Otherwise update current candle with tick
          const updatedLast = generateNextTick(last, selectedAsset);
          return [...prev.slice(0, -1), updatedLast];
        }
      });
    }, 2000); // Ticks every 2 seconds

    return () => clearInterval(interval);
  }, [isLive, selectedAsset, timeframe, candles.length]);

  // Update zones whenever candles or config changes
  useEffect(() => {
    if (candles.length > 0) {
      const newZones = detectFVGs(candles, config);
      setZones(newZones);
    }
  }, [candles, config]);

