          </div>
        </div>

        <div className="flex items-center gap-3 md:gap-4">
          {/* Timeframe Selector */}
          <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            {TIMEFRAMES.map(tf => (
              <button
                key={tf.value}
