                className={`px-3 py-1 rounded text-xs font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-white'}`}
              >
                {tf.label}
              </button>
            ))}
          </div>

          {/* Asset Selector */}
          <div className="relative group">
            <select 
              value={selectedAsset.symbol}
