import { Asset, Candle, Timeframe } from '../types';

const TIMEFRAME_MAP_BINANCE: Record<Timeframe, string> = {
  '1m': '1m',
  '5m': '5m',
  '15m': '15m',
  '1h': '1h',
  '4h': '4h',
  '1d': '1d',
};

// Proxies can be unstable, so we have a reliable fallback logic
const fetchYahooData = async (symbol: string, interval: string): Promise<Candle[]> => {
  // Using a common CORS proxy for demo purposes. 
  // In a production app, this would be a backend call.
  const proxyUrl = 'https://api.allorigins.win/get?url=';
  const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${interval}&range=5d`;

  try {
    const response = await fetch(proxyUrl + encodeURIComponent(yahooUrl));
    if (!response.ok) throw new Error('Proxy error');
    const data = JSON.parse((await response.json()).contents);

    const result = data.chart.result[0];
    const timestamps = result.timestamp;
    const { open, high, low, close } = result.indicators.quote[0];

    return timestamps.map((t: number, i: number) => ({
      time: t,
      open: open[i],
      high: high[i],
      low: low[i],
      close: close[i],
    })).filter((c: any) => c.open !== null);
  } catch (error) {
    console.warn(`Failed to fetch ${symbol} from Yahoo:`, error);
    return [];
  }
};

export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  // Logic for US30 (Dow Jones)
  if (asset.symbol === 'US30') {
    const yahooInterval = timeframe === '1d' ? '1d' : timeframe === '4h' ? '1h' : timeframe; // Yahoo limited intra-day
    return await fetchYahooData('^DJI', yahooInterval);
  }

  // Logic for Crypto (Binance)
  if (asset.symbol.includes('/USD') || asset.symbol === 'BTC/USD' || asset.symbol === 'ETH/USD' || asset.symbol === 'SOL/USD') {
    const binanceSymbol = asset.symbol.replace('/USD', 'USDT');
    const interval = TIMEFRAME_MAP_BINANCE[timeframe];

    try {
      const response = await fetch(`https://api.binance.com/api/v3/klines?symbol=${binanceSymbol}&interval=${interval}&limit=500`);
      if (!response.ok) throw new Error('Binance error');
      const data = await response.json();

      return data.map((d: any) => ({
        time: Math.floor(d[0] / 1000),
        open: parseFloat(d[1]),
        high: parseFloat(d[2]),
        low: parseFloat(d[3]),
        close: parseFloat(d[4]),
      }));
    } catch (error) {
      console.warn(`Failed to fetch ${binanceSymbol} from Binance:`, error);
      return [];
    }
  }

  // Fallback for GOLD and others
  const fallbackMap: Record<string, string> = {
    'GOLD': 'GC=F',
    'EUR/USD': 'EURUSD=X'
  };
  if (fallbackMap[asset.symbol]) {
    return await fetchYahooData(fallbackMap[asset.symbol], timeframe);
  }

  return [];
};

