const fetchYahooData = async (symbol: string, interval: string): Promise<Candle[]> => {
  const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${interval}&range=5d`;

  // Try proxies
  for (const proxy of PROXIES) {
    try {
      const targetUrl = proxy === PROXIES[0] ? proxy + encodeURIComponent(yahooUrl) : proxy + yahooUrl;
      const response = await fetch(targetUrl);
      if (!response.ok) continue;

      let data;
      if (proxy === PROXIES[0]) {
          const json = await response.json();
          data = JSON.parse(json.contents);
      } else {
          data = await response.json();
      }

      if (!data?.chart?.result?.[0]) continue;

      const result = data.chart.result[0];
      const timestamps = result.timestamp;
      const quote = result.indicators.quote[0];
      const { open, high, low, close } = quote;

      return timestamps.map((t: number, i: number) => ({
        time: t,
        open: open[i],
        high: high[i],
        low: low[i],
        close: close[i],
      })).filter((c: any) => c.open !== null && c.close !== null);
    } catch (error) {
      console.warn(`Proxy ${proxy} failed for ${symbol}:`, error);
    }
  }

  console.error(`All proxies failed for Yahoo Finance: ${symbol}`);
  return [];
};

