import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Candle, FVGZone, IndicatorConfig, FVGType, Asset, SUPPORTED_ASSETS, Timeframe, TIMEFRAMES } from './types';
import { generateMockCandles, injectFVGs } from './utils/mockDataGenerator';
import { detectFVGs } from './utils/fvgDetector';
import { analyzeMarket } from './services/geminiService';
import { fetchRealData } from './services/dataService';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [selectedAsset, setSelectedAsset] = useState<Asset>(SUPPORTED_ASSETS.find(a => a.symbol === 'US30') || SUPPORTED_ASSETS[0]);
  const [timeframe, setTimeframe] = useState<Timeframe>('15m');
  const [candles, setCandles] = useState<Candle[]>([]);
  const [zones, setZones] = useState<FVGZone[]>([]);
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const socketRef = useRef<WebSocket | null>(null);

  const [config, setConfig] = useState<IndicatorConfig>({
    bullColor: '#3b82f6',
    bearColor: '#ec4899',
    transparency: 100,
    lookback: 500,
    drawFilled: true,
    mitigationDetection: true
  });

  // Carregamento inicial de histórico
  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const realData = await fetchRealData(selectedAsset, timeframe);
      if (realData && realData.length > 0) {
        setCandles(realData);
      } else {
        const mock = generateMockCandles(200, selectedAsset, timeframe);
        setCandles(injectFVGs(mock, selectedAsset));
        setError('Histórico indisponível. Simulando dados.');
      }
    } catch (err) {
      setError('Erro de conexão. Simulando dados.');
      const mock = generateMockCandles(200, selectedAsset, timeframe);
      setCandles(injectFVGs(mock, selectedAsset));
    } finally {
      setLoading(false);
    }
  }, [selectedAsset, timeframe]);

  // Gerenciamento de WebSocket para Tempo Real (Binance)
  useEffect(() => {
    if (socketRef.current) {
        socketRef.current.close();
    }

    if (selectedAsset.symbol.includes('/USD')) {
        const symbol = selectedAsset.symbol.replace('/USD', 'usdt').toLowerCase();
        // Mapeamento de timeframe para Binance Stream
        const streamTf = timeframe === '1d' ? '1d' : timeframe === '4h' ? '4h' : timeframe === '1h' ? '1h' : timeframe;
        const socketUrl = `wss://stream.binance.com:9443/ws/${symbol}@kline_${streamTf}`;

        const socket = new WebSocket(socketUrl);
        socketRef.current = socket;

        socket.onmessage = (event) => {
            const data = JSON.parse(event.data);
            const k = data.k; // Kline data
            if (!k) return;

            const newCandle: Candle = {
                time: Math.floor(k.t / 1000),
                open: parseFloat(k.o),
                high: parseFloat(k.h),
                low: parseFloat(k.l),
                close: parseFloat(k.c)
            };

            setCandles(prev => {
                if (prev.length === 0) return [newCandle];
                const last = prev[prev.length - 1];

                // Se o timestamp for o mesmo, atualiza a última vela (movimento de preço)
                if (last.time === newCandle.time) {
                    const newArray = [...prev];
                    newArray[newArray.length - 1] = newCandle;
                    return newArray;
                } 
                // Se o timestamp for novo, adiciona nova vela ao array
                else if (newCandle.time > last.time) {
                    return [...prev, newCandle].slice(-1000); // Mantém buffer de 1000 velas
                }
                return prev;
            });
        };

        socket.onerror = () => setError('Erro no stream de tempo real.');
    } else {
        // Para ativos não-Binance (US30), usamos polling agressivo como fallback
        const pollInterval = setInterval(loadData, 15000);
        return () => clearInterval(pollInterval);
    }

    return () => {
        if (socketRef.current) socketRef.current.close();
    };
  }, [selectedAsset, timeframe]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  useEffect(() => {
    if (candles.length > 0) {
      const newZones = detectFVGs(candles, config);
      setZones(newZones);
    }
  }, [candles, config]);

  const handleRunAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, zones, selectedAsset);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200">
      <header className="flex items-center justify-between px-6 py-4 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-indigo-500/20 shadow-xl">
            <i className="fas fa-bolt text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight text-white leading-none">SMC LIVE</h1>
            <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">WebSocket Enabled Engine</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            {TIMEFRAMES.map(tf => (
              <button
                key={tf.value}
                onClick={() => setTimeframe(tf.value)}
                className={`px-2.5 py-1 rounded text-[11px] font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}
              >
                {tf.label}
              </button>
            ))}
          </div>

          <select 
            value={selectedAsset.symbol}
            onChange={(e) => {
              const asset = SUPPORTED_ASSETS.find(a => a.symbol === e.target.value);
              if (asset) setSelectedAsset(asset);
            }}
            className="bg-slate-800 border border-slate-700 text-white text-xs rounded-lg p-2 focus:ring-indigo-500 outline-none cursor-pointer font-bold"
          >
            {SUPPORTED_ASSETS.map(asset => (
              <option key={asset.symbol} value={asset.symbol}>{asset.symbol} - {asset.name}</option>
            ))}
          </select>

          <button 
            onClick={handleRunAnalysis}
            disabled={isAnalyzing || loading}
            className="flex items-center gap-2 px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 transition-all text-xs font-bold shadow-lg shadow-indigo-500/20"
          >
            {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>}
            IA ANALYZE
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <div className="flex-1 flex flex-col relative overflow-hidden p-2">
          {loading && (
            <div className="absolute inset-0 z-50 bg-slate-950/80 backdrop-blur-sm flex items-center justify-center">
              <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-sm font-bold text-slate-400 animate-pulse tracking-widest uppercase">Syncing {selectedAsset.symbol} WebSocket...</p>
              </div>
            </div>
          )}

          <div className="flex-1 bg-slate-900 rounded-xl border border-slate-800 shadow-inner overflow-hidden">
            <TradingChart candles={candles} zones={zones} config={config} asset={selectedAsset} />
          </div>

          <div className="grid grid-cols-4 gap-2 mt-2">
            <div className="bg-slate-900 p-3 rounded-lg border border-slate-800 flex flex-col relative overflow-hidden">
              <span className="text-[10px] text-slate-500 font-bold uppercase">Price</span>
              <span className="text-sm font-bold tabular-nums text-white flex items-center gap-2">
                {candles.length > 0 ? candles[candles.length - 1].close.toFixed(selectedAsset.decimals) : '---'}
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-ping"></div>
              </span>
            </div>
            <div className="bg-slate-900 p-3 rounded-lg border border-slate-800 flex flex-col">
              <span className="text-[10px] text-indigo-500 font-bold uppercase">Bullish FVG</span>
              <span className="text-sm font-bold text-indigo-400">{zones.filter(z => z.type === FVGType.BULLISH).length}</span>
            </div>
            <div className="bg-slate-900 p-3 rounded-lg border border-slate-800 flex flex-col">
              <span className="text-[10px] text-pink-500 font-bold uppercase">Bearish FVG</span>
              <span className="text-sm font-bold text-pink-400">{zones.filter(z => z.type === FVGType.BEARISH).length}</span>
            </div>
            <div className="bg-slate-900 p-3 rounded-lg border border-slate-800 flex flex-col">
              <span className="text-[10px] text-emerald-500 font-bold uppercase">Socket Status</span>
              <span className="text-sm font-bold text-emerald-400 flex items-center gap-1">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div> 
                ACTIVE
              </span>
            </div>
          </div>
        </div>

        <aside className="w-80 border-l border-slate-800 bg-slate-900/50 flex flex-col">
           <div className="p-4 border-b border-slate-800 flex items-center gap-2 bg-slate-900">
             <i className="fas fa-robot text-indigo-500"></i>
             <h2 className="text-sm font-bold uppercase tracking-wider text-slate-300">SMC Insight</h2>
           </div>
           <div className="flex-1 p-4 overflow-y-auto text-sm leading-relaxed text-slate-400">
             {!aiAnalysis ? (
