                 <i className="fas fa-brain text-4xl mb-4"></i>
                 <p className="px-6 text-xs font-medium italic">Análise de IA disponível via WebSocket.</p>
               </div>
             ) : (
               <div className="prose prose-invert prose-sm">
                 {aiAnalysis.split('\n').map((line, i) => <p key={i} className="mb-4 bg-slate-800/30 p-2 rounded border border-slate-800/50">{line}</p>)}
