import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time } from 'lightweight-charts';
import { Candle, FVGZone, IndicatorConfig, FVGType, Asset } from '../types';

interface Props {
  candles: Candle[];
  zones: FVGZone[];
  config: IndicatorConfig;
  asset: Asset;
  utcOffset: number; // Offset em horas
}

const TradingChart: React.FC<Props> = ({ candles, zones, config, asset, utcOffset }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);

  const hexToRgba = (hex: string, alpha: number) => {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#020617' },
        textColor: '#94a3b8',
        fontSize: 11,
        fontFamily: 'JetBrains Mono',
      },
      grid: {
        vertLines: { color: '#0f172a' },
        horzLines: { color: '#0f172a' },
      },
      crosshair: {
        mode: 0,
        vertLine: { color: '#334155', labelBackgroundColor: '#4f46e5' },
        horzLine: { color: '#334155', labelBackgroundColor: '#4f46e5' },
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
        secondsVisible: false,
      },
      rightPriceScale: {
        borderColor: '#1e293b',
        autoScale: true,
      },
      localization: {
        // Formatação personalizada para tooltips se necessário
      }
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    const handleResize = () => {
      if (chartContainerRef.current) {
        chart.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };

    window.addEventListener('resize', handleResize);

    const updateOverlay = () => {
        if (!canvasRef.current || !chartRef.current || !seriesRef.current || candles.length === 0) return;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const currentWidth = chartContainerRef.current?.clientWidth || 0;
        const currentHeight = chartContainerRef.current?.clientHeight || 0;

        if (canvas.width !== currentWidth || canvas.height !== currentHeight) {
          canvas.width = currentWidth;
          canvas.height = currentHeight;
        }

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        const timeScale = chart.timeScale();
        const activeSeries = seriesRef.current;

        zones.forEach(zone => {
            // Ajustamos o tempo da zona com o offset para bater com as velas no gráfico
            const zStart = (zone.startTime + offsetInSeconds) as Time;
            const zEnd = (zone.mitigated && zone.mitigationTime 
                ? zone.mitigationTime + offsetInSeconds 
                : candles[candles.length - 1].time + offsetInSeconds) as Time;

            const t1 = timeScale.timeToCoordinate(zStart);
            const t2 = timeScale.timeToCoordinate(zEnd);

            const p1 = activeSeries.priceToCoordinate(zone.top);
            const p2 = activeSeries.priceToCoordinate(zone.bottom);

            if (t1 === null || p1 === null || p2 === null) return;

            const x = t1;
            const y = Math.min(p1, p2);
            const w = (t2 !== null ? t2 : canvas.width) - t1;
            const h = Math.abs(p1 - p2);

            if (w <= 0) return;

            const color = zone.type === FVGType.BULLISH ? config.bullColor : config.bearColor;
            const baseOpacity = config.transparency / 255;

            ctx.fillStyle = hexToRgba(color, baseOpacity);
            ctx.fillRect(x, y, w, h);

            ctx.strokeStyle = hexToRgba(color, baseOpacity + 0.3);
            ctx.lineWidth = 1;
            ctx.strokeRect(x, y, w, h);
        });
    };

    chart.timeScale().subscribeVisibleTimeRangeChange(updateOverlay);
    const interval = setInterval(updateOverlay, 30);

    return () => {
      window.removeEventListener('resize', handleResize);
      clearInterval(interval);
      chart.remove();
    };
  }, [asset.symbol, offsetInSeconds]);

  const lastCandleTimeRef = useRef<number>(0);

  useEffect(() => {
    if (seriesRef.current && candles.length > 0) {
      const lastCandle = candles[candles.length - 1];
      const displayTime = lastCandle.time + offsetInSeconds;

      if (displayTime === lastCandleTimeRef.current) {
          seriesRef.current.update({
            time: displayTime as Time,
            open: lastCandle.open,
            high: lastCandle.high,
            low: lastCandle.low,
            close: lastCandle.close,
          });
      } else {
          const formattedData = candles.map(c => ({
            time: (c.time + offsetInSeconds) as Time,
            open: c.open,
            high: c.high,
            low: c.low,
            close: c.close,
          }));
          seriesRef.current.setData(formattedData);
          lastCandleTimeRef.current = displayTime;
      }
    }
  }, [candles, offsetInSeconds]);

  return (
    <div className="relative w-full h-full flex flex-col bg-[#020617]">
        <div ref={chartContainerRef} className="flex-1 w-full h-full" />
        <canvas 
            ref={canvasRef} 
            className="absolute top-0 left-0 pointer-events-none w-full h-full"
        />

        <div className="absolute top-3 left-3 pointer-events-none flex flex-col gap-1.5">
             <div className="bg-slate-900/90 backdrop-blur-md px-3 py-1.5 rounded-lg border border-slate-700/50 flex items-center gap-2 shadow-xl">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[11px] font-bold text-slate-200 jetbrains tracking-wider uppercase">
                    {asset.symbol} • {asset.name}
                </span>
             </div>
        </div>

        {!isReady && (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-950/50 backdrop-blur-sm">
                <div className="flex flex-col items-center gap-3">
                    <div className="w-8 h-8 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-xs font-bold text-slate-500 jetbrains tracking-widest uppercase">Booting SMC Engine...</span>
                </div>
            </div>
        )}
    </div>
  );
};

export default TradingChart;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Candle, FVGZone, IndicatorConfig, FVGType, Asset, SUPPORTED_ASSETS, Timeframe, TIMEFRAMES, UTC_OFFSETS } from './types';
import { generateMockCandles, injectFVGs } from './utils/mockDataGenerator';
import { detectFVGs } from './utils/fvgDetector';
import { analyzeMarket } from './services/geminiService';
import { fetchRealData } from './services/dataService';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [selectedAsset, setSelectedAsset] = useState<Asset>(SUPPORTED_ASSETS.find(a => a.symbol === 'US30') || SUPPORTED_ASSETS[0]);
  const [timeframe, setTimeframe] = useState<Timeframe>('15m');
  const [utcOffset, setUtcOffset] = useState<number>(-3); // Default para Brasília (UTC -3)
  const [candles, setCandles] = useState<Candle[]>([]);
  const [zones, setZones] = useState<FVGZone[]>([]);
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [latency, setLatency] = useState<string>('0ms');

  const socketRef = useRef<WebSocket | null>(null);
  const tickTimerRef = useRef<number | null>(null);

  const [config, setConfig] = useState<IndicatorConfig>({
    bullColor: '#3b82f6',
    bearColor: '#ec4899',
    transparency: 100,
    lookback: 500,
    drawFilled: true,
    mitigationDetection: true
  });

  const loadData = useCallback(async () => {
    setError(null);
    try {
      const startTime = Date.now();
      const realData = await fetchRealData(selectedAsset, timeframe);
      const endTime = Date.now();

      setLatency(`${endTime - startTime}ms`);

      if (realData && realData.length > 0) {
        setCandles(realData);
      } else if (candles.length === 0) {
        const mock = generateMockCandles(200, selectedAsset, timeframe);
        setCandles(injectFVGs(mock, selectedAsset));
        setError('Histórico indisponível. Usando simulação.');
      }
    } catch (err) {
      if (candles.length === 0) {
        const mock = generateMockCandles(200, selectedAsset, timeframe);
        setCandles(injectFVGs(mock, selectedAsset));
      }
    } finally {
      setLoading(false);
    }
  }, [selectedAsset, timeframe, candles.length]);

  useEffect(() => {
    if (tickTimerRef.current) clearInterval(tickTimerRef.current);

    if (!selectedAsset.symbol.includes('/USD')) {
      tickTimerRef.current = window.setInterval(() => {
        setCandles(prev => {
          if (prev.length === 0) return prev;
          const last = { ...prev[prev.length - 1] };
          const drift = (Math.random() - 0.5) * (last.close * 0.0001);
          last.close += drift;
          last.high = Math.max(last.high, last.close);
          last.low = Math.min(last.low, last.close);

          const newArray = [...prev];
          newArray[newArray.length - 1] = last;
          return newArray;
        });
      }, 500);
    }

    return () => {
      if (tickTimerRef.current) clearInterval(tickTimerRef.current);
    };
  }, [selectedAsset, loading]);

  useEffect(() => {
    if (socketRef.current) socketRef.current.close();

    if (selectedAsset.symbol.includes('/USD')) {
        const symbol = selectedAsset.symbol.replace('/USD', 'usdt').toLowerCase();
        const streamTf = timeframe === '1d' ? '1d' : timeframe === '4h' ? '4h' : timeframe === '1h' ? '1h' : timeframe;
        const socketUrl = `wss://stream.binance.com:9443/ws/${symbol}@kline_${streamTf}`;

        const socket = new WebSocket(socketUrl);
        socketRef.current = socket;

        socket.onmessage = (event) => {
            const data = JSON.parse(event.data);
            const k = data.k;
            if (!k) return;

            const newCandle: Candle = {
                time: Math.floor(k.t / 1000),
                open: parseFloat(k.o),
                high: parseFloat(k.h),
                low: parseFloat(k.l),
                close: parseFloat(k.c)
            };

            setCandles(prev => {
                if (prev.length === 0) return [newCandle];
                const last = prev[prev.length - 1];
                if (last.time === newCandle.time) {
                    const newArray = [...prev];
                    newArray[newArray.length - 1] = newCandle;
                    return newArray;
                } else if (newCandle.time > last.time) {
                    return [...prev, newCandle].slice(-1000);
                }
                return prev;
            });
            setLatency('~0ms (WebSocket)');
        };
    } else {
        const pollInterval = setInterval(loadData, 8000);
        return () => clearInterval(pollInterval);
    }

    return () => {
        if (socketRef.current) socketRef.current.close();
    };
  }, [selectedAsset, timeframe, loadData]);

  useEffect(() => {
    loadData();
  }, [selectedAsset, timeframe]);

  useEffect(() => {
    if (candles.length > 0) {
      const newZones = detectFVGs(candles, config);
      setZones(newZones);
    }
  }, [candles, config]);

  const handleRunAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, zones, selectedAsset);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200">
      <header className="flex items-center justify-between px-6 py-4 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-indigo-500/20 shadow-xl">
            <i className="fas fa-clock text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight text-white leading-none">SMC PRO ENGINE</h1>
            <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">Global Timezone Sync</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {/* UTC Selector */}
          <div className="flex items-center gap-2 bg-slate-800 border border-slate-700 rounded-lg px-2">
            <i className="fas fa-globe text-[10px] text-slate-500"></i>
            <select 
              value={utcOffset}
              onChange={(e) => setUtcOffset(parseInt(e.target.value))}
              className="bg-transparent text-white text-[11px] rounded p-1.5 focus:ring-0 outline-none cursor-pointer font-bold jetbrains"
            >
              {UTC_OFFSETS.map(offset => (
                <option key={offset.value} value={offset.value} className="bg-slate-900">{offset.label}</option>
              ))}
            </select>
          </div>

          <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            {TIMEFRAMES.map(tf => (
              <button
                key={tf.value}
                onClick={() => setTimeframe(tf.value)}
                className={`px-2.5 py-1 rounded text-[11px] font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}
              >
                {tf.label}
              </button>
            ))}
          </div>

          <select 
            value={selectedAsset.symbol}
            onChange={(e) => {
              const asset = SUPPORTED_ASSETS.find(a => a.symbol === e.target.value);
              if (asset) setSelectedAsset(asset);
            }}
            className="bg-slate-800 border border-slate-700 text-white text-xs rounded-lg p-2 focus:ring-indigo-500 outline-none cursor-pointer font-bold"
          >
            {SUPPORTED_ASSETS.map(asset => (
              <option key={asset.symbol} value={asset.symbol}>{asset.symbol} - {asset.name}</option>
            ))}
          </select>

          <button 
