import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Candle, FVGZone, IndicatorConfig, FVGType, Asset, SUPPORTED_ASSETS, Timeframe, TIMEFRAMES, UTC_OFFSETS } from './types';
import { generateMockCandles, injectFVGs } from './utils/mockDataGenerator';
import { detectFVGs } from './utils/fvgDetector';
import { analyzeMarket } from './services/geminiService';
import { fetchRealData } from './services/dataService';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [selectedAsset, setSelectedAsset] = useState<Asset>(SUPPORTED_ASSETS.find(a => a.symbol === 'US30') || SUPPORTED_ASSETS[0]);
  const [timeframe, setTimeframe] = useState<Timeframe>('15m');
  const [utcOffset, setUtcOffset] = useState<number>(-3); // Default para Brasília (UTC -3)
  const [candles, setCandles] = useState<Candle[]>([]);
  const [zones, setZones] = useState<FVGZone[]>([]);
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [latency, setLatency] = useState<string>('0ms');

  const socketRef = useRef<WebSocket | null>(null);
  const tickTimerRef = useRef<number | null>(null);

  const [config, setConfig] = useState<IndicatorConfig>({
    bullColor: '#3b82f6',
    bearColor: '#ec4899',
    transparency: 100,
    lookback: 500,
    drawFilled: true,
    mitigationDetection: true
  });

  // Carregamento de dados com limpeza de estado para troca imediata de visualização
  const loadData = useCallback(async (isInitialLoad = false) => {
    if (isInitialLoad) {
      setLoading(true);
      setCandles([]); // Limpa o gráfico para forçar a renderização do novo tempo gráfico
      setZones([]);
    }
    setError(null);

    try {
      const startTime = Date.now();
      const realData = await fetchRealData(selectedAsset, timeframe);
      const endTime = Date.now();

      setLatency(`${endTime - startTime}ms`);

      if (realData && realData.length > 0) {
        setCandles(realData);
      } else if (candles.length === 0) {
        const mock = generateMockCandles(200, selectedAsset, timeframe);
        setCandles(injectFVGs(mock, selectedAsset));
        setError('Histórico real indisponível. Usando simulação.');
      }
    } catch (err) {
      if (candles.length === 0) {
        const mock = generateMockCandles(200, selectedAsset, timeframe);
        setCandles(injectFVGs(mock, selectedAsset));
      }
    } finally {
      setLoading(false);
    }
  }, [selectedAsset, timeframe]);

  // Micro-Tick Engine para simulação de movimento em ativos com delay (US30)
  useEffect(() => {
    if (tickTimerRef.current) clearInterval(tickTimerRef.current);

    if (!selectedAsset.symbol.includes('/USD') && !loading) {
      tickTimerRef.current = window.setInterval(() => {
        setCandles(prev => {
          if (prev.length === 0) return prev;
          const last = { ...prev[prev.length - 1] };
          const drift = (Math.random() - 0.5) * (last.close * 0.00005);
          last.close += drift;
          last.high = Math.max(last.high, last.close);
          last.low = Math.min(last.low, last.close);

          const newArray = [...prev];
          newArray[newArray.length - 1] = last;
          return newArray;
        });
      }, 1000);
    }

    return () => {
      if (tickTimerRef.current) clearInterval(tickTimerRef.current);
    };
  }, [selectedAsset, loading]);

  // WebSocket management - Reinicia sempre que o ativo ou timeframe muda
  useEffect(() => {
    if (socketRef.current) {
      socketRef.current.close();
      socketRef.current = null;
    }

    if (selectedAsset.symbol.includes('/USD')) {
        const symbol = selectedAsset.symbol.replace('/USD', 'usdt').toLowerCase();
        const streamTf = timeframe; // Binance suporta 1m, 5m, 15m, 1h, 4h, 1d nativamente
        const socketUrl = `wss://stream.binance.com:9443/ws/${symbol}@kline_${streamTf}`;

        const socket = new WebSocket(socketUrl);
        socketRef.current = socket;

        socket.onmessage = (event) => {
            const data = JSON.parse(event.data);
            const k = data.k;
            if (!k) return;

            const newCandle: Candle = {
                time: Math.floor(k.t / 1000),
                open: parseFloat(k.o),
                high: parseFloat(k.h),
                low: parseFloat(k.l),
                close: parseFloat(k.c)
            };

            setCandles(prev => {
                if (prev.length === 0) return [newCandle];
                const last = prev[prev.length - 1];
                if (last.time === newCandle.time) {
                    const newArray = [...prev];
                    newArray[newArray.length - 1] = newCandle;
                    return newArray;
                } else if (newCandle.time > last.time) {
                    return [...prev, newCandle].slice(-1000);
                }
                return prev;
            });
            setLatency('Real-Time (WS)');
        };

        socket.onclose = () => console.log('Socket closed');
        socket.onerror = (e) => console.error('Socket error:', e);
    } else {
        const pollInterval = setInterval(() => loadData(false), 10000);
        return () => clearInterval(pollInterval);
    }

    return () => {
        if (socketRef.current) socketRef.current.close();
    };
  }, [selectedAsset, timeframe, loadData]);

  // Efeito principal de gatilho para troca de contexto (Asset/Timeframe)
  useEffect(() => {
    loadData(true);
  }, [selectedAsset, timeframe]);

  useEffect(() => {
    if (candles.length > 0) {
      const newZones = detectFVGs(candles, config);
      setZones(newZones);
    } else {
      setZones([]);
    }
  }, [candles, config]);

  const handleRunAnalysis = async () => {
    if (candles.length === 0) return;
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, zones, selectedAsset);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200">
      <header className="flex items-center justify-between px-6 py-4 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-indigo-500/20 shadow-xl">
            <i className="fas fa-chart-line text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight text-white leading-none">SMC PRO ANALYZER</h1>
            <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">Fair Value Gap Engine</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-800 border border-slate-700 rounded-lg px-2">
            <i className="fas fa-globe text-[10px] text-slate-500"></i>
            <select 
              value={utcOffset}
              onChange={(e) => setUtcOffset(parseInt(e.target.value))}
              className="bg-transparent text-white text-[11px] rounded p-1.5 focus:ring-0 outline-none cursor-pointer font-bold jetbrains"
            >
              {UTC_OFFSETS.map(offset => (
                <option key={offset.value} value={offset.value} className="bg-slate-900">{offset.label}</option>
              ))}
            </select>
          </div>

          <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            {TIMEFRAMES.map(tf => (
              <button
                key={tf.value}
                onClick={() => setTimeframe(tf.value)}
                className={`px-2.5 py-1 rounded text-[11px] font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}
              >
                {tf.label}
              </button>
            ))}
          </div>

          <select 
            value={selectedAsset.symbol}
            onChange={(e) => {
              const asset = SUPPORTED_ASSETS.find(a => a.symbol === e.target.value);
              if (asset) setSelectedAsset(asset);
            }}
            className="bg-slate-800 border border-slate-700 text-white text-xs rounded-lg p-2 focus:ring-indigo-500 outline-none cursor-pointer font-bold"
          >
            {SUPPORTED_ASSETS.map(asset => (
              <option key={asset.symbol} value={asset.symbol}>{asset.symbol} - {asset.name}</option>
            ))}
          </select>

          <button 
            onClick={handleRunAnalysis}
            disabled={isAnalyzing || loading || candles.length === 0}
            className="flex items-center gap-2 px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 transition-all text-xs font-bold shadow-lg shadow-indigo-500/20"
          >
            {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-brain"></i>}
            IA ANALYSIS
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <div className="flex-1 flex flex-col relative overflow-hidden p-2">
          {loading && (
            <div className="absolute inset-0 z-50 bg-slate-950/80 backdrop-blur-sm flex items-center justify-center">
              <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-sm font-bold text-slate-400 animate-pulse tracking-widest uppercase">
                  Sincronizando {timeframe} para {selectedAsset.symbol}...
                </p>
              </div>
            </div>
          )}

          <div className="flex-1 bg-slate-900 rounded-xl border border-slate-800 shadow-inner overflow-hidden relative">
            <TradingChart candles={candles} zones={zones} config={config} asset={selectedAsset} utcOffset={utcOffset} />

            <div className="absolute bottom-4 left-4 flex items-center gap-3 pointer-events-none">
                <div className="bg-slate-900/90 backdrop-blur-sm px-2 py-1 rounded border border-slate-700/50 flex items-center gap-2">
                    <div className={`w-1.5 h-1.5 rounded-full ${selectedAsset.symbol.includes('/USD') ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`}></div>
                    <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">
                        Mode: {selectedAsset.symbol.includes('/USD') ? 'Direct WebSocket' : 'API Polling'}
                    </span>
                </div>
                <div className="bg-slate-900/90 backdrop-blur-sm px-2 py-1 rounded border border-slate-700/50 flex items-center gap-2">
                    <i className="fas fa-tachometer-alt text-[9px] text-slate-500"></i>
                    <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">
                        Ping: {latency}
                    </span>
                </div>
            </div>
          </div>

          <div className="grid grid-cols-4 gap-2 mt-2">
            <div className="bg-slate-900 p-3 rounded-lg border border-slate-800 flex flex-col relative overflow-hidden">
              <span className="text-[10px] text-slate-500 font-bold uppercase">Price ({selectedAsset.symbol})</span>
              <span className="text-sm font-bold tabular-nums text-white flex items-center gap-2">
