const PROXIES = [
  'https://api.allorigins.win/get?url=',
  'https://corsproxy.io/?',
];

const fetchYahooData = async (symbol: string, interval: string, range: string = '1d'): Promise<any> => {
  const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${interval}&range=${range}`;

  for (const proxy of PROXIES) {
    try {
      const targetUrl = proxy === PROXIES[0] ? proxy + encodeURIComponent(yahooUrl) : proxy + yahooUrl;
      const response = await fetch(targetUrl);
      if (!response.ok) continue;

      let data;
      if (proxy === PROXIES[0]) {
          const json = await response.json();
          data = JSON.parse(json.contents);
      } else {
          data = await response.json();
      }

      return data?.chart?.result?.[0];
    } catch (error) {
      console.warn(`Proxy ${proxy} failed for ${symbol}:`, error);
    }
  }
  return null;
};

export const fetchCorrelationData = async (): Promise<CorrelationData[]> => {
  const targets = [
    { symbol: '^VIX', name: 'VIX (Fear)', corr: 'negative' as const },
    { symbol: '^IXIC', name: 'US100 (Nasdaq)', corr: 'positive' as const },
    { symbol: '^GSPC', name: 'US500 (S&P)', corr: 'positive' as const },
    { symbol: 'DX-Y.NYB', name: 'DXY (Dollar)', corr: 'negative' as const },
  ];

  const results: CorrelationData[] = [];

  for (const target of targets) {
    const data = await fetchYahooData(target.symbol, '5m', '1d');
    if (data) {
      const meta = data.meta;
      results.push({
        symbol: target.symbol,
        name: target.name,
        price: meta.regularMarketPrice,
        change: ((meta.regularMarketPrice - meta.previousClose) / meta.previousClose) * 100,
        correlation: target.corr
      });
    }
  }
  return results;
};

export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  if (asset.symbol === 'US30') {
    const yahooInterval = timeframe === '4h' ? '1h' : timeframe; 
    const result = await fetchYahooData('^DJI', yahooInterval, '5d');
    if (!result) return [];

    const timestamps = result.timestamp;
    const quote = result.indicators.quote[0];
    const { open, high, low, close } = quote;

    return timestamps.map((t: number, i: number) => ({
      time: t,
      open: open[i],
      high: high[i],
      low: low[i],
      close: close[i],
    })).filter((c: any) => c.open !== null && c.close !== null);
  }

  if (asset.symbol.includes('/USD')) {
    const binanceSymbol = asset.symbol.replace('/USD', 'USDT');
    const interval = timeframe;
    try {
      const response = await fetch(`https://api.binance.com/api/v3/klines?symbol=${binanceSymbol}&interval=${interval}&limit=500`);
      if (!response.ok) throw new Error('Binance failed');
      const data = await response.json();
      return data.map((d: any) => ({
        time: Math.floor(d[0] / 1000),
        open: parseFloat(d[1]),
        high: parseFloat(d[2]),
        low: parseFloat(d[3]),
        close: parseFloat(d[4]),
      }));
    } catch (error) { console.warn(error); }
  }

  return [];
};

import { GoogleGenAI } from "@google/genai";
import { Candle, FVGZone, Asset, CorrelationData } from "../types";

export const analyzeMarket = async (
  candles: Candle[], 
  zones: FVGZone[], 
  asset: Asset, 
  correlations: CorrelationData[] = [],
  context: string = "Standard"
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const currentPrice = candles[candles.length - 1].close;
  const bullishCount = zones.filter(z => z.type === 'BULLISH' && !z.mitigated).length;
  const bearishCount = zones.filter(z => z.type === 'BEARISH' && !z.mitigated).length;

  const corrContext = correlations.map(c => 
    `${c.name}: ${c.change.toFixed(2)}% (${c.correlation === 'positive' ? 'Correlação Direta' : 'Inversa'})`
  ).join('\n');

  const prompt = `
    Como um estrategista sênior de Smart Money Concepts (SMC) e Macroeconomia, analise ${asset.name} (${asset.symbol}):
    Contexto da Análise: ${context}

    DADOS ATUAIS:
    - Preço: ${currentPrice.toFixed(asset.decimals)}
    - Imbalanços (FVGs): ${bullishCount} Alta / ${bearishCount} Baixa

    QUADRO MACRO E CORRELAÇÕES:
    ${corrContext}

    INSTRUÇÕES:
    1. Se o contexto for "Pre-Open", avalie o provável gap e a direção inicial com base no VIX e Nasdaq.
    2. Se o contexto for "Post-Open", avalie a reação institucional imediata.
    3. Identifique o "Draw on Liquidity" (para onde o preço está sendo puxado).

    Forneça uma resposta curta, direta e técnica em Português (Brasil).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Análise indisponível.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar análise macro.";
  }
};

