const PROXIES = [
  'https://api.allorigins.win/get?url=',
  'https://corsproxy.io/?',
];

const fetchYahooData = async (symbol: string, interval: string, range: string = '1d'): Promise<any> => {
  const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${interval}&range=${range}`;

  for (const proxy of PROXIES) {
    try {
      const targetUrl = proxy === PROXIES[0] ? proxy + encodeURIComponent(yahooUrl) : proxy + yahooUrl;
      const response = await fetch(targetUrl);
      if (!response.ok) continue;

      let data;
      if (proxy === PROXIES[0]) {
          const json = await response.json();
          data = JSON.parse(json.contents);
      } else {
          data = await response.json();
      }

      return data?.chart?.result?.[0];
    } catch (error) {
      console.warn(`Proxy ${proxy} failed for ${symbol}:`, error);
    }
  }
  return null;
};

export const fetchCorrelationData = async (): Promise<CorrelationData[]> => {
  const targets = [
    { symbol: '^VIX', name: 'VIX (Miedo)', corr: 'negative' as const },
    { symbol: '^IXIC', name: 'US100 (Nasdaq)', corr: 'positive' as const },
    { symbol: '^GSPC', name: 'US500 (S&P)', corr: 'positive' as const },
    { symbol: 'DX-Y.NYB', name: 'DXY (Dollar)', corr: 'negative' as const },
  ];

  const results: CorrelationData[] = [];
  for (const target of targets) {
    const data = await fetchYahooData(target.symbol, '5m', '1d');
    if (data) {
      const meta = data.meta;
      results.push({
        symbol: target.symbol,
        name: target.name,
        price: meta.regularMarketPrice,
        change: ((meta.regularMarketPrice - (meta.previousClose || meta.regularMarketPrice)) / (meta.previousClose || meta.regularMarketPrice)) * 100,
        correlation: target.corr
      });
    }
  }
  return results;
};

export const fetchDowSummary = async (): Promise<DowSummary> => {
  // Para ser performático via proxy, analisamos os componentes principais
  // Em uma aplicação real, usaríamos um endpoint de batch quotes
  const subset = DOW_30_TICKERS.slice(0, 20); // Analisamos os 20 principais como amostra significativa
  let advancing = 0;
  let declining = 0;

  // Realizamos buscas em paralelo para agilizar
  const promises = subset.map(ticker => fetchYahooData(ticker, '1d', '1d'));
  const results = await Promise.all(promises);

  results.forEach(data => {
    if (data && data.meta) {
      const change = data.meta.regularMarketPrice - data.meta.previousClose;
      if (change >= 0) advancing++;
      else declining++;
    }
  });

  // Extrapolamos para 30 baseado na amostra de 20 para manter a UI estável
  const ratio = 30 / subset.length;

  return {
    advancing: Math.round(advancing * ratio),
    declining: Math.round(declining * ratio),
    total: 30
  };
};

export const calculateVolumePressure = (candles: Candle[]): VolumePressure => {
  if (candles.length === 0) return { buyPercent: 50, sellPercent: 50, total: 0 };

  let buyVol = 0;
  let sellVol = 0;

  const recent = candles.slice(-15);
  recent.forEach(c => {
    const body = Math.abs(c.close - c.open);
    const range = c.high - c.low || 0.001;
    const vol = (c.volume || 1000);

    if (c.close > c.open) {
      buyVol += vol * (body / range + 0.5);
      sellVol += vol * (1 - (body / range + 0.5));
    } else {
      sellVol += vol * (body / range + 0.5);
      buyVol += vol * (1 - (body / range + 0.5));
    }
  });

  const total = buyVol + sellVol;
  return {
    buyPercent: (buyVol / total) * 100,
    sellPercent: (sellVol / total) * 100,
    total: total
  };
};

export const detectOpeningGap = (candles: Candle[]): GapData => {
  if (candles.length < 2) return { value: 0, percent: 0, type: 'none' };

  let prevDayClose = 0;
  let todayOpen = 0;

  for (let i = candles.length - 1; i > 0; i--) {
    const currDate = new Date(candles[i].time * 1000).getDate();
    const prevDate = new Date(candles[i-1].time * 1000).getDate();

    if (currDate !== prevDate) {
      prevDayClose = candles[i-1].close;
      todayOpen = candles[i].open;
      break;
    }
  }

  if (prevDayClose === 0) return { value: 0, percent: 0, type: 'none' };

  const diff = todayOpen - prevDayClose;
  const pct = (diff / prevDayClose) * 100;

  return {
    value: diff,
    percent: pct,
    type: pct > 0.05 ? 'up' : pct < -0.05 ? 'down' : 'none'
  };
};

export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  if (asset.symbol === 'US30') {
    const result = await fetchYahooData('^DJI', timeframe, '5d');
    if (!result) return [];

    const timestamps = result.timestamp;
    const quote = result.indicators.quote[0];
    const { open, high, low, close, volume } = quote;

    return timestamps.map((t: number, i: number) => ({
      time: t,
      open: open[i],
      high: high[i],
      low: low[i],
      close: close[i],
      volume: volume ? volume[i] : 0
    })).filter((c: any) => c.open !== null && c.close !== null);
  }

  if (asset.symbol.includes('/USD')) {
    const binanceSymbol = asset.symbol.replace('/USD', 'USDT');
    try {
      const response = await fetch(`https://api.binance.com/api/v3/klines?symbol=${binanceSymbol}&interval=${timeframe}&limit=500`);
      const data = await response.json();
      return data.map((d: any) => ({
        time: Math.floor(d[0] / 1000),
        open: parseFloat(d[1]),
        high: parseFloat(d[2]),
        low: parseFloat(d[3]),
        close: parseFloat(d[4]),
        volume: parseFloat(d[5])
      }));
    } catch (e) { return []; }
  }
  return [];
};

