    ];
    return events;
};

export const fetchDowSummary = async (): Promise<DowSummary> => {
  const subset = DOW_30_TICKERS.slice(0, 20); 
  let advancing = 0;
  let declining = 0;

  const promises = subset.map(ticker => fetchYahooData(ticker, '1d', '1d'));
  const results = await Promise.all(promises);

  results.forEach(data => {
    if (data && data.meta) {
      const change = data.meta.regularMarketPrice - data.meta.previousClose;
      if (change >= 0) advancing++;
      else declining++;
    }
  });

  const ratio = 30 / subset.length;

  return {
    advancing: Math.round(advancing * ratio),
    declining: Math.round(declining * ratio),
    total: 30
  };
};

export const calculateVolumePressure = (candles: Candle[]): VolumePressure => {
  if (candles.length === 0) return { buyPercent: 50, sellPercent: 50, total: 0 };

  let buyVol = 0;
  let sellVol = 0;

  const recent = candles.slice(-15);
  recent.forEach(c => {
    const body = Math.abs(c.close - c.open);
    const range = c.high - c.low || 0.001;
    const vol = (c.volume || 1000);

    if (c.close > c.open) {
      buyVol += vol * (body / range + 0.5);
      sellVol += vol * (1 - (body / range + 0.5));
    } else {
      sellVol += vol * (body / range + 0.5);
      buyVol += vol * (1 - (body / range + 0.5));
    }
  });

  const total = buyVol + sellVol;
  return {
    buyPercent: (buyVol / total) * 100,
    sellPercent: (sellVol / total) * 100,
    total: total
  };
};

export const detectOpeningGap = (candles: Candle[]): GapData => {
  if (candles.length < 2) return { value: 0, percent: 0, type: 'none' };

  let prevDayClose = 0;
  let todayOpen = 0;

  for (let i = candles.length - 1; i > 0; i--) {
    const currDate = new Date(candles[i].time * 1000).getDate();
    const prevDate = new Date(candles[i-1].time * 1000).getDate();

    if (currDate !== prevDate) {
      prevDayClose = candles[i-1].close;
      todayOpen = candles[i].open;
      break;
    }
  }

  if (prevDayClose === 0) return { value: 0, percent: 0, type: 'none' };

  const diff = todayOpen - prevDayClose;
  const pct = (diff / prevDayClose) * 100;

  return {
    value: diff,
    percent: pct,
    type: pct > 0.05 ? 'up' : pct < -0.05 ? 'down' : 'none'
  };
};

export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  if (asset.symbol === 'US30') {
    const result = await fetchYahooData('^DJI', timeframe, '5d');
    if (!result) return [];

    const timestamps = result.timestamp;
    const quote = result.indicators.quote[0];
    const { open, high, low, close, volume } = quote;

    return timestamps.map((t: number, i: number) => ({
      time: t,
      open: open[i],
      high: high[i],
      low: low[i],
      close: close[i],
      volume: volume ? volume[i] : 0
    })).filter((c: any) => c.open !== null && c.close !== null);
  }

  if (asset.symbol.includes('/USD')) {
    const binanceSymbol = asset.symbol.replace('/USD', 'USDT');
    try {
      const response = await fetch(`https://api.binance.com/api/v3/klines?symbol=${binanceSymbol}&interval=${timeframe}&limit=500`);
      const data = await response.json();
      return data.map((d: any) => ({
        time: Math.floor(d[0] / 1000),
        open: parseFloat(d[1]),
        high: parseFloat(d[2]),
        low: parseFloat(d[3]),
        close: parseFloat(d[4]),
        volume: parseFloat(d[5])
      }));
    } catch (e) { return []; }
  }
  return [];
};

import { GoogleGenAI } from "@google/genai";
import { Candle, FVGZone, Asset, CorrelationData, EconomicEvent } from "../types";

export const analyzeMarket = async (
  candles: Candle[], 
  zones: FVGZone[], 
  asset: Asset, 
  correlations: CorrelationData[] = [],
  events: EconomicEvent[] = [],
  context: string = "Standard"
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const currentPrice = candles[candles.length - 1].close;
  const bullishCount = zones.filter(z => z.type === 'BULLISH' && !z.mitigated).length;
  const bearishCount = zones.filter(z => z.type === 'BEARISH' && !z.mitigated).length;

  const corrContext = correlations.map(c => 
    `${c.name}: ${c.change.toFixed(2)}% (${c.correlation === 'positive' ? 'Correlação Direta' : 'Inversa'})`
  ).join('\n');

  const eventContext = events.map(e => 
    `- ${e.title}: Impacto ${e.impact}, Sentimento ${e.sentiment}. (${e.description})`
  ).join('\n');

  const prompt = `
    Como um estrategista sênior de Smart Money Concepts (SMC) e Macroeconomia, analise ${asset.name} (${asset.symbol}):
    Contexto da Análise: ${context}

    DADOS ATUAIS:
    - Preço: ${currentPrice.toFixed(asset.decimals)}
    - Imbalanços (FVGs): ${bullishCount} Alta / ${bearishCount} Baixa

    EVENTOS ECONÔMICOS E NOTÍCIAS:
    ${eventContext || "Nenhum evento relevante detectado."}

    QUADRO MACRO E CORRELAÇÕES:
    ${corrContext}

    INSTRUÇÕES:
    1. Avalie como as notícias e discursos recentes afetam o sentimento institucional.
    2. Identifique se os FVGs estão alinhados com a direção do sentimento macro (Notícias + Correlações).
    3. Determine se há um "Event Driven Bias" (viés dirigido por eventos).

    Forneça uma resposta curta, direta e técnica em Português (Brasil).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Análise indisponível.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar análise macro.";
  }
};

