export const fetchDowSummary = async (): Promise<{ summary: DowSummary, details: DowCompanyDetails[] }> => {
  // CRÍTICO: Usar o endpoint de QUOTE em lote para as 30 empresas de uma vez só.
  // Isso resolve o problema de "não trazer os dados" devido a excesso de requisições ao proxy.
  const symbols = DOW_30_TICKERS.join(',');
  const quoteUrl = `https://query1.finance.yahoo.com/v7/finance/quote?symbols=${symbols}`;

  const data = await fetchFromYahoo(quoteUrl);
  const details: DowCompanyDetails[] = [];
  let advancing = 0;
  let declining = 0;

  if (data?.quoteResponse?.result) {
    data.quoteResponse.result.forEach((quote: any) => {
      const change = quote.regularMarketChangePercent || 0;
      const status = change >= 0 ? 'BUY' : 'SELL';

      if (status === 'BUY') advancing++;
      else declining++;

      details.push({
        symbol: quote.symbol,
        change: change,
        status: status as 'BUY' | 'SELL'
      });
    });
  }

  // Se o API falhar totalmente, retornamos dados simulados para não quebrar a UI
  if (details.length === 0) {
    DOW_30_TICKERS.forEach(ticker => {
      const mockChange = (Math.random() - 0.4) * 2;
      details.push({
        symbol: ticker,
        change: mockChange,
        status: mockChange >= 0 ? 'BUY' : 'SELL'
      });
      if (mockChange >= 0) advancing++; else declining++;
    });
  }

  return {
    summary: {
      advancing,
      declining,
      total: DOW_30_TICKERS.length
    },
    details: details.sort((a, b) => b.change - a.change)
  };
};

export const calculateVolumePressure = (candles: Candle[]): VolumePressure => {
  if (candles.length === 0) return { buyPercent: 50, sellPercent: 50, total: 0 };

  let buyVol = 0;
  let sellVol = 0;

  const recent = candles.slice(-15);
  recent.forEach(c => {
    const body = Math.abs(c.close - c.open);
    const range = c.high - c.low || 0.001;
    const vol = (c.volume || 1000);

    if (c.close > c.open) {
      buyVol += vol * (body / range + 0.5);
      sellVol += vol * (1 - (body / range + 0.5));
    } else {
      sellVol += vol * (body / range + 0.5);
      buyVol += vol * (1 - (body / range + 0.5));
    }
  });

  const total = buyVol + sellVol || 1;
  return {
    buyPercent: (buyVol / total) * 100,
    sellPercent: (sellVol / total) * 100,
    total: total
  };
};

export const detectOpeningGap = (candles: Candle[]): GapData => {
  if (candles.length < 2) return { value: 0, percent: 0, type: 'none' };

  let prevDayClose = 0;
  let todayOpen = 0;

  for (let i = candles.length - 1; i > 0; i--) {
    const currDate = new Date(candles[i].time * 1000).getDate();
    const prevDate = new Date(candles[i-1].time * 1000).getDate();

    if (currDate !== prevDate) {
      prevDayClose = candles[i-1].close;
      todayOpen = candles[i].open;
      break;
    }
  }

  if (prevDayClose === 0) return { value: 0, percent: 0, type: 'none' };

  const diff = todayOpen - prevDayClose;
  const pct = (diff / prevDayClose) * 100;

  return {
    value: diff,
    percent: pct,
    type: pct > 0.05 ? 'up' : pct < -0.05 ? 'down' : 'none'
  };
};

export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  if (asset.symbol === 'US30') {
    const result = await fetchYahooData('^DJI', timeframe, '5d');
    if (!result) return [];

    const timestamps = result.timestamp;
    const quote = result.indicators.quote[0];
    const { open, high, low, close, volume } = quote;

    return timestamps.map((t: number, i: number) => ({
      time: t,
      open: open[i],
      high: high[i],
      low: low[i],
      close: close[i],
      volume: volume ? volume[i] : 0
    })).filter((c: any) => c.open !== null && c.close !== null);
  }

  if (asset.symbol.includes('/USD')) {
    const binanceSymbol = asset.symbol.replace('/USD', 'USDT');
    try {
      const response = await fetch(`https://api.binance.com/api/v3/klines?symbol=${binanceSymbol}&interval=${timeframe}&limit=500`);
      const data = await response.json();
      return data.map((d: any) => ({
        time: Math.floor(d[0] / 1000),
        open: parseFloat(d[1]),
        high: parseFloat(d[2]),
        low: parseFloat(d[3]),
        close: parseFloat(d[4]),
        volume: parseFloat(d[5])
      }));
    } catch (e) { return []; }
  }
  return [];
};

