import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time } from 'lightweight-charts';
import { Candle, Asset, GapData } from '../types';

interface Props {
  candles: Candle[];
  asset: Asset;
  utcOffset: number;
  gap: GapData;
}

const TradingChart: React.FC<Props> = ({ candles, asset, utcOffset, gap }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#020617' },
        textColor: '#94a3b8',
        fontSize: 11,
        fontFamily: 'Inter, sans-serif',
      },
      grid: {
        vertLines: { color: '#0f172a' },
        horzLines: { color: '#0f172a' },
      },
      crosshair: {
        mode: 0,
        vertLine: { color: '#334155', labelBackgroundColor: '#4f46e5' },
        horzLine: { color: '#334155', labelBackgroundColor: '#4f46e5' },
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
      },
      rightPriceScale: {
        borderColor: '#1e293b',
      }
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    const handleResize = () => {
      if (chartContainerRef.current) {
        chart.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };

    window.addEventListener('resize', handleResize);

    // Overlay Drawing Loop for Gap
    const drawGapOverlay = () => {
      if (!canvasRef.current || !chartRef.current || !seriesRef.current || candles.length === 0 || !gap.startIndex) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const canvas = canvasRef.current;
      const currentWidth = chartContainerRef.current?.clientWidth || 0;
      const currentHeight = chartContainerRef.current?.clientHeight || 0;

      if (canvas.width !== currentWidth || canvas.height !== currentHeight) {
        canvas.width = currentWidth;
        canvas.height = currentHeight;
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      if (gap.type === 'none' || !gap.prevClose || !gap.openPrice) return;

      const timeScale = chartRef.current.timeScale();
      const firstCandleTime = (candles[gap.startIndex].time + offsetInSeconds) as Time;
      const x = timeScale.timeToCoordinate(firstCandleTime);

      const p1 = seriesRef.current.priceToCoordinate(gap.prevClose);
      const p2 = seriesRef.current.priceToCoordinate(gap.openPrice);

      if (x !== null && p1 !== null && p2 !== null) {
        // Draw Gap Zone
        ctx.fillStyle = gap.type === 'up' ? 'rgba(16, 185, 129, 0.15)' : 'rgba(239, 68, 68, 0.15)';
        ctx.fillRect(x - 50, Math.min(p1, p2), canvas.width - x + 50, Math.abs(p1 - p2));

        // Draw Gap Line
        ctx.strokeStyle = gap.type === 'up' ? '#10b981' : '#ef4444';
        ctx.setLineDash([5, 5]);
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(x - 60, p1);
        ctx.lineTo(canvas.width, p1);
        ctx.stroke();

        // Label
        ctx.font = 'bold 9px Inter';
        ctx.fillStyle = ctx.strokeStyle;
        ctx.fillText(`OPENING GAP: ${gap.percent.toFixed(2)}%`, x + 10, Math.min(p1, p2) - 5);
        ctx.setLineDash([]);
      }
    };

    const interval = setInterval(drawGapOverlay, 100);
    chart.timeScale().subscribeVisibleTimeRangeChange(drawGapOverlay);

    return () => {
      window.removeEventListener('resize', handleResize);
      clearInterval(interval);
      chart.remove();
    };
  }, [asset.symbol, gap]);

  useEffect(() => {
    if (seriesRef.current) {
      if (candles.length === 0) {
        seriesRef.current.setData([]);
        return;
      }
      const formattedData = candles.map(c => ({
        time: (c.time + offsetInSeconds) as Time,
        open: c.open,
        high: c.high,
        low: c.low,
        close: c.close,
      }));
      seriesRef.current.setData(formattedData);
    }
  }, [candles, offsetInSeconds]);

  return (
    <div className="relative w-full h-full bg-[#020617]">
        <div ref={chartContainerRef} className="w-full h-full" />
        <canvas ref={canvasRef} className="absolute top-0 left-0 pointer-events-none w-full h-full z-10" />

        {!isReady && (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-950/50 backdrop-blur-sm">
                <div className="flex flex-col items-center gap-3">
                    <div className="w-8 h-8 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Initialising Chart Engine...</span>
                </div>
            </div>
        )}
    </div>
  );
};

export default TradingChart;

