  type: 'up' | 'down' | 'none';
  startIndex?: number;
  prevClose?: number;
  openPrice?: number;
}

export interface EconomicEvent {
  id: string;
  time: number;
  title: string;
  impact: 'HIGH' | 'MEDIUM' | 'LOW';
