          </div>
          <select value={selectedAsset.symbol} onChange={(e) => {
              const asset = SUPPORTED_ASSETS.find(a => a.symbol === e.target.value)!;
              setSelectedAsset(asset);
              if (asset.symbol === 'HK50') setUtcOffset(8);
              else setUtcOffset(-5);
          }} className="bg-slate-800 border border-slate-700 text-white text-[11px] rounded p-2 font-bold outline-none hover:border-slate-600 transition-colors">
            {SUPPORTED_ASSETS.map(a => <option key={a.symbol} value={a.symbol}>{a.symbol} - {a.name}</option>)}
