import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time } from 'lightweight-charts';
import { Candle, Asset, GapData, SMCZone, ZoneType, FVGType } from '../types';

interface Props {
  candles: Candle[];
  asset: Asset;
  utcOffset: number;
  gap: GapData;
  zones: SMCZone[];
  loading: boolean;
}

const TradingChart: React.FC<Props> = ({ candles, asset, utcOffset, gap, zones, loading }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);
  const initialLoadRef = useRef(true);

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    initialLoadRef.current = true;
  }, [asset.symbol]);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#020617' },
        textColor: '#94a3b8',
        fontSize: 11,
        fontFamily: 'Inter, sans-serif',
      },
      grid: {
        vertLines: { color: '#0f172a' },
        horzLines: { color: '#0f172a' },
      },
      crosshair: {
        mode: 0,
        vertLine: { color: '#4f46e5', labelBackgroundColor: '#4f46e5', width: 1 },
        horzLine: { color: '#4f46e5', labelBackgroundColor: '#4f46e5', width: 1 },
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
        secondsVisible: false,
      },
      rightPriceScale: {
        borderColor: '#1e293b',
        autoScale: true,
      }
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    const handleResize = () => {
      if (chartContainerRef.current) {
        chart.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };

    window.addEventListener('resize', handleResize);

    // --- RENDER OVERLAY (SMC ZONES & GAPS) ---
    const drawOverlay = () => {
      if (!canvasRef.current || !chartRef.current || !seriesRef.current || candles.length === 0) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const canvas = canvasRef.current;
      const currentWidth = chartContainerRef.current?.clientWidth || 0;
      const currentHeight = chartContainerRef.current?.clientHeight || 0;

      if (canvas.width !== currentWidth || canvas.height !== currentHeight) {
        canvas.width = currentWidth;
        canvas.height = currentHeight;
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const timeScale = chartRef.current.timeScale();
      const priceScale = seriesRef.current;

      // 1. Draw SMC Zones (FVG / OB / BOS)
      zones.forEach(zone => {
        const xStart = timeScale.timeToCoordinate((zone.startTime + offsetInSeconds) as Time);
        const yTop = priceScale.priceToCoordinate(zone.top);
        const yBottom = priceScale.priceToCoordinate(zone.bottom);

        if (xStart !== null && yTop !== null && yBottom !== null) {
          const width = canvas.width - xStart;
          const height = Math.abs(yBottom - yTop);

          // Estilo baseado no tipo de zona
          if (zone.type === ZoneType.FVG) {
            ctx.fillStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(16, 185, 129, 0.12)' : 'rgba(239, 68, 68, 0.12)';
            ctx.strokeStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(16, 185, 129, 0.3)' : 'rgba(239, 68, 68, 0.3)';
          } else if (zone.type === ZoneType.ORDER_BLOCK) {
            ctx.fillStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(79, 70, 229, 0.08)' : 'rgba(217, 70, 239, 0.08)';
            ctx.strokeStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(79, 70, 229, 0.4)' : 'rgba(217, 70, 239, 0.4)';
          } else {
             ctx.fillStyle = 'transparent';
             ctx.strokeStyle = 'rgba(148, 163, 184, 0.2)';
          }

          if (!zone.mitigated) {
            ctx.fillRect(xStart, Math.min(yTop, yBottom), width, height);
            ctx.strokeRect(xStart, Math.min(yTop, yBottom), width, height);

            // Label
            ctx.font = '700 9px Inter';
            ctx.fillStyle = ctx.strokeStyle;
            ctx.fillText(zone.label, xStart + 5, Math.min(yTop, yBottom) + 12);
          }
        }
      });

      // 2. Draw Opening Gap
      if (gap.type !== 'none' && gap.startIndex !== undefined && gap.prevClose && gap.openPrice) {
        const firstCandleTime = (candles[gap.startIndex].time + offsetInSeconds) as Time;
        const xGap = timeScale.timeToCoordinate(firstCandleTime);
        const pg1 = priceScale.priceToCoordinate(gap.prevClose);
        const pg2 = priceScale.priceToCoordinate(gap.openPrice);

        if (xGap !== null && pg1 !== null && pg2 !== null) {
          ctx.fillStyle = gap.type === 'up' ? 'rgba(16, 185, 129, 0.15)' : 'rgba(239, 68, 68, 0.15)';
          ctx.fillRect(xGap - 40, Math.min(pg1, pg2), canvas.width - xGap + 40, Math.abs(pg1 - pg2));
          ctx.strokeStyle = gap.type === 'up' ? '#10b981' : '#ef4444';
          ctx.setLineDash([4, 4]);
          ctx.beginPath();
          ctx.moveTo(xGap - 50, pg1);
          ctx.lineTo(canvas.width, pg1);
          ctx.stroke();
          ctx.setLineDash([]);
          ctx.font = 'bold 10px JetBrains Mono';
          ctx.fillStyle = ctx.strokeStyle;
          ctx.fillText(`GAP ${gap.percent.toFixed(2)}%`, xGap + 10, Math.min(pg1, pg2) - 6);
        }
      }
    };

    const interval = setInterval(drawOverlay, 100);
    chart.timeScale().subscribeVisibleTimeRangeChange(drawOverlay);

    return () => {
      window.removeEventListener('resize', handleResize);
      clearInterval(interval);
      chart.remove();
    };
  }, [asset.symbol, gap, zones, offsetInSeconds]);

  useEffect(() => {
    if (seriesRef.current && chartRef.current) {
      if (candles.length === 0) {
        seriesRef.current.setData([]);
        initialLoadRef.current = true;
        return;
      }

      const formattedData = candles.map(c => ({
        time: (c.time + offsetInSeconds) as Time,
        open: c.open,
        high: c.high,
        low: c.low,
        close: c.close,
      }));

      seriesRef.current.setData(formattedData);

      if (initialLoadRef.current && formattedData.length > 0) {
        chartRef.current.timeScale().fitContent();
        initialLoadRef.current = false;
      }
    }
  }, [candles, offsetInSeconds]);

  return (
    <div className="relative w-full h-full bg-[#020617]">
        <div ref={chartContainerRef} className="w-full h-full" />
        <canvas ref={canvasRef} className="absolute top-0 left-0 pointer-events-none w-full h-full z-10" />

        {(loading || !isReady) && (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-950/60 backdrop-blur-md z-50">
                <div className="flex flex-col items-center gap-4">
                    <div className="relative">
                        <div className="w-12 h-12 border-4 border-indigo-500/20 rounded-full"></div>
                        <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin absolute top-0 left-0"></div>
                    </div>
                    <div className="flex flex-col items-center">
                        <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.3em] text-center animate-pulse">Sincronizando Nodes</span>
                        <span className="text-[9px] text-slate-500 font-bold uppercase mt-1 tracking-widest">{asset.symbol} - Real-time Feed</span>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default TradingChart;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Candle, Asset, SUPPORTED_ASSETS, Timeframe, TIMEFRAMES, UTC_OFFSETS, CorrelationData, MarketBreadthSummary, BreadthCompanyDetails, VolumePressure, GapData, EconomicEvent, EntryRecommendation, SMCZone, FVGType } from './types';
import { analyzeMarket } from './services/geminiService';
import { fetchRealData, fetchCorrelationData, fetchMarketBreadth, calculateVolumePressure, detectOpeningGap, fetchEconomicEvents } from './services/dataService';
import { detectSMCZones } from './utils/fvgDetector';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [selectedAsset, setSelectedAsset] = useState<Asset>(SUPPORTED_ASSETS[0]);
  const [timeframe, setTimeframe] = useState<Timeframe>('1m');
  const [utcOffset, setUtcOffset] = useState<number>(-3);
  const [candles, setCandles] = useState<Candle[]>([]);
  const [correlations, setCorrelations] = useState<CorrelationData[]>([]);
  const [events, setEvents] = useState<EconomicEvent[]>([]);
  const [breadthSummary, setBreadthSummary] = useState<MarketBreadthSummary>({ advancing: 0, declining: 0, total: 0 });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [lastUpdate, setLastUpdate] = useState<Date>(new Date());

  // Ref para manter as velas atualizadas via WebSocket sem re-renderizar o App inteiro a cada tick
  const candlesRef = useRef<Candle[]>([]);

  // Clock Local
  const [localTime, setLocalTime] = useState<string>('');
  useEffect(() => {
    const timer = setInterval(() => {
      setLocalTime(new Date().toLocaleTimeString([], { hour12: false }));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // --- WEBSOCKET ENGINE (BINANCE) ---
  useEffect(() => {
    setLoading(true);
    let ws: WebSocket;

    const initData = async () => {
      // 1. Fetch History
      const history = await fetchRealData(selectedAsset, timeframe);
      setCandles(history);
      candlesRef.current = history;
      setLoading(false);

      // 2. Connect WebSocket for Real-time
      // Binance symbol format: btcusdt@kline_1m
      const binanceSymbol = selectedAsset.symbol.toLowerCase().replace('/', '');
      const interval = timeframe;
      ws = new WebSocket(`wss://stream.binance.com:9443/ws/${binanceSymbol}@kline_${interval}`);

      ws.onmessage = (event) => {
        const msg = JSON.parse(event.data);
        const k = msg.k;
        const newCandle: Candle = {
          time: k.t / 1000,
          open: parseFloat(k.o),
          high: parseFloat(k.h),
          low: parseFloat(k.l),
          close: parseFloat(k.c),
          volume: parseFloat(k.v)
        };

        setCandles(prev => {
          if (prev.length === 0) return [newCandle];
          const last = prev[prev.length - 1];
          // Se for a mesma vela, atualiza. Se for nova, adiciona.
          if (last.time === newCandle.time) {
            const updated = [...prev.slice(0, -1), newCandle];
            candlesRef.current = updated;
            return updated;
          } else {
            const updated = [...prev, newCandle];
            candlesRef.current = updated;
            return updated;
          }
        });
        setLastUpdate(new Date());
      };
    };

    initData();

    // Global Data (Correlations/Events)
    fetchCorrelationData(selectedAsset.symbol).then(setCorrelations);
    fetchEconomicEvents().then(setEvents);

    return () => {
      if (ws) ws.close();
    };
  }, [selectedAsset, timeframe]);

  const smcZones = useMemo(() => {
    if (candles.length === 0) return [];
    return detectSMCZones(candles, { lookback: 200, mitigationDetection: true, drawFilled: true });
  }, [candles]);

  const entryRecommendation = useMemo<EntryRecommendation>(() => {
    if (candles.length < 10) return { price: 0, type: 'NONE', zoneType: '', target: 0, stopLoss: 0 };
    const currentPrice = candles[candles.length - 1].close;
    const activeZones = smcZones.filter(z => !z.mitigated);

    const buyZone = activeZones.find(z => z.sentiment === FVGType.BULLISH && z.top < currentPrice);
    const sellZone = activeZones.find(z => z.sentiment === FVGType.BEARISH && z.bottom > currentPrice);

    if (buyZone) return { price: buyZone.top, type: 'BUY', zoneType: buyZone.label, target: buyZone.top * 1.02, stopLoss: buyZone.bottom };
    if (sellZone) return { price: sellZone.bottom, type: 'SELL', zoneType: sellZone.label, target: sellZone.bottom * 0.98, stopLoss: sellZone.top };

    return { price: 0, type: 'NONE', zoneType: '', target: 0, stopLoss: 0 };
  }, [smcZones, candles]);

  const handleManualAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, selectedAsset, correlations, events, "Live Price Action");
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col h-screen bg-[#08090b] text-[#d1d4dc] overflow-hidden font-['Inter']">
      <header className="flex items-center justify-between px-4 py-2 bg-[#131722] border-b border-[#2a2e39] shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center">
              <i className="fas fa-chart-line text-white text-sm"></i>
            </div>
            <span className="text-sm font-bold tracking-tight text-white">SENTINEL SMC</span>
          </div>

          <div className="h-6 w-px bg-[#2a2e39]"></div>

          <select 
            value={selectedAsset.symbol} 
            onChange={(e) => setSelectedAsset(SUPPORTED_ASSETS.find(a => a.symbol === e.target.value)!)}
            className="bg-transparent text-white font-bold text-sm outline-none cursor-pointer hover:text-indigo-400 transition-colors"
          >
            {SUPPORTED_ASSETS.map(a => <option key={a.symbol} value={a.symbol} className="bg-[#131722]">{a.symbol}</option>)}
          </select>

          <div className="flex bg-[#2a2e39]/40 p-0.5 rounded">
            {TIMEFRAMES.slice(0, 4).map(tf => (
              <button 
                key={tf.value} 
                onClick={() => setTimeframe(tf.value)} 
                className={`px-3 py-1 rounded text-[11px] font-bold transition-all ${timeframe === tf.value ? 'bg-[#2962ff] text-white' : 'text-[#787b86] hover:text-[#d1d4dc]'}`}
              >
                {tf.label}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 px-3 py-1 bg-[#2a2e39]/30 rounded-full border border-[#2a2e39]">
            <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_#10b981]"></span>
            <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Live WebSocket</span>
          </div>

          <div className="flex flex-col items-end">
            <span className="text-[10px] font-bold text-[#787b86] uppercase leading-none">{localTime}</span>
            <span className="text-[9px] text-indigo-400 font-bold mt-1">UTC {utcOffset >= 0 ? '+' : ''}{utcOffset}</span>
          </div>

          <button 
            onClick={handleManualAnalysis} 
            disabled={isAnalyzing} 
            className="px-4 py-1.5 bg-[#2962ff] hover:bg-[#1e4bd8] text-white rounded text-xs font-bold transition-all flex items-center gap-2 disabled:opacity-50"
          >
            {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-robot"></i>} AI SCAN
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Gráfico Principal */}
        <div className="flex-1 flex flex-col relative bg-[#08090b]">
          <div className="flex-1 relative">
            <TradingChart 
              candles={candles} 
