          {/* Status Bar Inferior (Estilo TradingView) */}
          <div className="h-9 bg-[#131722] border-t border-[#2a2e39] flex items-center justify-between px-4">
             <div className="flex items-center gap-4 text-[11px] font-medium text-[#787b86]">
                <span className="flex items-center gap-1.5">
