/**
 * Busca dados históricos da Binance para o gráfico.
 * @param asset O ativo selecionado (Ex: BTC/USDT)
 * @param timeframe O tempo gráfico (Ex: 1m, 15m)
 */
export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  try {
    const symbol = asset.symbol.replace('/', '');
    const limit = 500;
    const url = `https://api.binance.com/api/v3/klines?symbol=${symbol}&interval=${timeframe}&limit=${limit}`;

    const response = await fetch(url);
    if (!response.ok) throw new Error("Binance API Error");

    const data = await response.json();

    return data.map((d: any) => ({
      time: d[0] / 1000,
      open: parseFloat(d[1]),
      high: parseFloat(d[2]),
      low: parseFloat(d[3]),
      close: parseFloat(d[4]),
      volume: parseFloat(d[5])
    }));
  } catch (error) {
    console.error("Fetch history failed:", error);
    return [];
  }
};

