import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time, CrosshairMode } from 'lightweight-charts';
import { Candle, Asset, GapData, SMCZone, ZoneType, FVGType } from '../types';

interface Props {
  candles: Candle[];
  asset: Asset;
  utcOffset: number;
  gap: GapData;
  zones: SMCZone[];
  loading: boolean;
}

const TradingChart: React.FC<Props> = ({ candles, asset, utcOffset, gap, zones, loading }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);
  const initialLoadRef = useRef(true);

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    initialLoadRef.current = true;
  }, [asset.symbol]);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#08090b' },
        textColor: '#d1d4dc',
        fontSize: 12,
        fontFamily: "'Inter', sans-serif",
      },
      grid: {
        vertLines: { color: 'rgba(42, 46, 57, 0.3)' },
        horzLines: { color: 'rgba(42, 46, 57, 0.3)' },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
        vertLine: { color: '#787b86', labelBackgroundColor: '#131722', width: 1, style: 2 },
        horzLine: { color: '#787b86', labelBackgroundColor: '#131722', width: 1, style: 2 },
      },
      timeScale: {
        borderColor: '#2a2e39',
        timeVisible: true,
        secondsVisible: false,
        barSpacing: 10,
      },
      rightPriceScale: {
        borderColor: '#2a2e39',
        autoScale: true,
      },
      handleScale: {
        mouseWheel: true,
        pinch: true,
      },
      handleScroll: {
        mouseWheel: true,
        pressedMouseMove: true,
      }
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#089981',
      downColor: '#f23645',
      borderVisible: false,
      wickUpColor: '#089981',
      wickDownColor: '#f23645',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    const handleResize = () => {
      if (chartContainerRef.current) {
        chart.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };

    window.addEventListener('resize', handleResize);

    const drawOverlay = () => {
      if (!canvasRef.current || !chartRef.current || !seriesRef.current || candles.length === 0) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const canvas = canvasRef.current;
      const container = chartContainerRef.current;
      if (!container) return;

      if (canvas.width !== container.clientWidth || canvas.height !== container.clientHeight) {
        canvas.width = container.clientWidth;
        canvas.height = container.clientHeight;
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const timeScale = chartRef.current.timeScale();
      const priceScale = seriesRef.current;

      zones.forEach(zone => {
        const xStart = timeScale.timeToCoordinate(zone.startTime as Time);
        const yTop = priceScale.priceToCoordinate(zone.top);
        const yBottom = priceScale.priceToCoordinate(zone.bottom);

        if (xStart !== null && yTop !== null && yBottom !== null) {
          const width = canvas.width - xStart;
          const height = Math.abs(yBottom - yTop);

          if (zone.type === ZoneType.FVG) {
            ctx.fillStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(8, 153, 129, 0.08)' : 'rgba(242, 54, 69, 0.08)';
            ctx.strokeStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(8, 153, 129, 0.3)' : 'rgba(242, 54, 69, 0.3)';
          } else {
            ctx.fillStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(41, 98, 255, 0.05)' : 'rgba(156, 39, 176, 0.05)';
            ctx.strokeStyle = zone.sentiment === FVGType.BULLISH ? 'rgba(41, 98, 255, 0.3)' : 'rgba(156, 39, 176, 0.3)';
          }

          if (!zone.mitigated) {
            ctx.setLineDash([2, 2]);
            ctx.fillRect(xStart, Math.min(yTop, yBottom), width, height);
            ctx.strokeRect(xStart, Math.min(yTop, yBottom), width, height);
            ctx.setLineDash([]);

            ctx.font = 'bold 10px Inter';
            ctx.fillStyle = ctx.strokeStyle;
            ctx.fillText(zone.label, xStart + 8, Math.min(yTop, yBottom) + 14);
          }
        }
      });
    };

    const animFrame = () => {
      drawOverlay();
      requestAnimationFrame(animFrame);
    };
    const frameId = requestAnimationFrame(animFrame);

    return () => {
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(frameId);
      chart.remove();
    };
  }, [asset.symbol, zones, candles.length]);

  useEffect(() => {
    if (seriesRef.current && chartRef.current) {
      if (candles.length === 0) {
        seriesRef.current.setData([]);
        return;
      }

      const formattedData = candles.map(c => ({
        time: c.time as Time,
        open: c.open,
        high: c.high,
        low: c.low,
        close: c.close,
      }));

      seriesRef.current.setData(formattedData);

      if (initialLoadRef.current && formattedData.length > 0) {
        chartRef.current.timeScale().fitContent();
        initialLoadRef.current = false;
      }
    }
  }, [candles]);

  return (
    <div className="relative w-full h-full bg-[#08090b]">
        <div ref={chartContainerRef} className="w-full h-full" />
        <canvas ref={canvasRef} className="absolute top-0 left-0 pointer-events-none w-full h-full z-10" />

        {loading && (
            <div className="absolute inset-0 flex items-center justify-center bg-[#08090b]/80 backdrop-blur-sm z-50">
                <div className="flex flex-col items-center gap-3">
                    <div className="w-8 h-8 border-2 border-[#2962ff] border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[10px] font-bold text-[#787b86] uppercase tracking-[0.2em]">Estabelecendo Conexão Stream</span>
                </div>
            </div>
        )}
    </div>
  );
};

