            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
              <span className="text-[10px] text-slate-500 font-black uppercase block mb-1 tracking-widest">Last Update</span>
              <span className="text-lg font-black jetbrains text-slate-300">{lastUpdate.toLocaleTimeString([], { hour12: false })}</span>
