import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Candle, Asset, SUPPORTED_ASSETS, Timeframe, TIMEFRAMES, UTC_OFFSETS, CorrelationData, MarketBreadthSummary, BreadthCompanyDetails, VolumePressure, GapData, EconomicEvent, EntryRecommendation, SMCZone, FVGType } from './types';
import { analyzeMarket } from './services/geminiService';
import { fetchRealData, fetchCorrelationData, fetchMarketBreadth, calculateVolumePressure, detectOpeningGap, fetchEconomicEvents } from './services/dataService';
import { detectSMCZones } from './utils/fvgDetector';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [selectedAsset, setSelectedAsset] = useState<Asset>(SUPPORTED_ASSETS[0]);
  const [timeframe, setTimeframe] = useState<Timeframe>('15m');
  const [utcOffset, setUtcOffset] = useState<number>(8); // Default HK (+8)
  const [candles, setCandles] = useState<Candle[]>([]);
  const [correlations, setCorrelations] = useState<CorrelationData[]>([]);
  const [events, setEvents] = useState<EconomicEvent[]>([]);
  const [breadthSummary, setBreadthSummary] = useState<MarketBreadthSummary>({ advancing: 0, declining: 0, total: 0 });
  const [breadthDetails, setBreadthDetails] = useState<BreadthCompanyDetails[]>([]);
  const [isBreadthModalOpen, setIsBreadthModalOpen] = useState(false);
  const [volumePressure, setVolumePressure] = useState<VolumePressure>({ buyPercent: 50, sellPercent: 50, total: 0 });
  const [gap, setGap] = useState<GapData>({ value: 0, percent: 0, type: 'none' });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [latency, setLatency] = useState<string>('0ms');
  const [nyTime, setNyTime] = useState<string>('');

  // Clock NY
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      const ny = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/New_York',
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
      }).format(now);
      setNyTime(ny);
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const loadData = useCallback(async (isInitialLoad = false) => {
    if (isInitialLoad) {
      setLoading(true);
      setCandles([]); 
    }

    try {
      const start = Date.now();
      const [candleData, corrData, breadthRes, eventData] = await Promise.all([
        fetchRealData(selectedAsset, timeframe),
        fetchCorrelationData(selectedAsset.symbol),
        fetchMarketBreadth(selectedAsset.symbol),
        fetchEconomicEvents()
      ]);

      setLatency(`${Date.now() - start}ms`);
      setCorrelations(corrData);
      setBreadthSummary(breadthRes.summary);
      setBreadthDetails(breadthRes.details);
      setEvents(eventData);

      if (candleData.length > 0) {
        setCandles(candleData);
        const vPres = calculateVolumePressure(candleData);
        const gData = detectOpeningGap(candleData, selectedAsset);
        setVolumePressure(vPres);
        setGap(gData);
      }
    } catch (err) {
      console.error("Data load failed:", err);
    } finally {
      if (isInitialLoad) setLoading(false);
    }
  }, [selectedAsset, timeframe]);

  useEffect(() => {
    loadData(true);
    const interval = setInterval(() => loadData(false), 30000);
    return () => clearInterval(interval);
  }, [selectedAsset, timeframe, loadData]);

  // Tick Simulator Avançado: Cria novas barras e move o preço
  useEffect(() => {
    if (candles.length === 0 || loading) return;

    const tfSeconds = TIMEFRAMES.find(t => t.value === timeframe)?.seconds || 900;

    const tickInterval = setInterval(() => {
      setCandles(prev => {
        if (prev.length === 0) return prev;
        const last = prev[prev.length - 1];
        const nowUnix = Math.floor(Date.now() / 1000);

        // Verifica se é hora de criar uma nova vela (Nova Barra)
        if (nowUnix >= last.time + tfSeconds) {
          const newCandle: Candle = {
            time: last.time + tfSeconds,
            open: last.close,
            high: last.close,
            low: last.close,
            close: last.close,
            volume: 0
          };
          return [...prev, newCandle];
        }

        // Caso contrário, apenas atualiza a vela atual (Wiggle)
        const volatility = selectedAsset.basePrice * 0.00015;
        const change = (Math.random() - 0.5) * volatility;
        const newClose = last.close + change;

        const updatedLast = {
          ...last,
          close: newClose,
          high: Math.max(last.high, newClose),
          low: Math.min(last.low, newClose)
        };
        return [...prev.slice(0, -1), updatedLast];
      });
    }, 1000);

    return () => clearInterval(tickInterval);
  }, [candles.length, loading, selectedAsset, timeframe]);

  const smcZones = useMemo(() => {
    return detectSMCZones(candles, { lookback: 200, mitigationDetection: true, drawFilled: true });
  }, [candles]);

  const sentimentScore = useMemo(() => {
    let points = 0;
    let maxPoints = 0;

    maxPoints += 3;
    const advRatio = breadthSummary.advancing / (breadthSummary.total || 1);
    if (advRatio > 0.7) points += 3;
    else if (advRatio > 0.55) points += 2;
    else if (advRatio > 0.45) points += 1;
    else if (advRatio < 0.3) points -= 3;
    else if (advRatio < 0.45) points -= 2;

    maxPoints += 3;
    let corrPoints = 0;
    correlations.forEach(c => {
      const isPositive = c.change > 0;
      if (c.correlation === 'positive') corrPoints += isPositive ? 0.5 : -0.5;
      else corrPoints += isPositive ? -0.5 : 0.5;
    });
    points += Math.max(-3, Math.min(3, corrPoints));

    maxPoints += 2;
    if (volumePressure.buyPercent > 65) points += 2;
    else if (volumePressure.buyPercent > 55) points += 1;
    else if (volumePressure.sellPercent > 65) points -= 2;
    else if (volumePressure.sellPercent > 55) points -= 1;

    maxPoints += 1;
    if (gap.type === 'up') points += 1;
    else if (gap.type === 'down') points -= 1;

    const normalized = (points / (maxPoints || 1)) * 100;
    const absScore = Math.abs(normalized);

    let direction: 'COMPRA' | 'VENDA' | 'NEUTRO' = 'NEUTRO';
    let strength = 'FRACO';
    let color = 'text-slate-400';
    let bgColor = 'bg-slate-800/40';

    if (normalized > 10) {
      direction = 'COMPRA';
      color = 'text-emerald-500';
      bgColor = 'bg-emerald-500/20';
      if (absScore > 70) strength = 'FORTE';
      else if (absScore > 35) strength = 'MODERADO';
    } else if (normalized < -10) {
      direction = 'VENDA';
      color = 'text-rose-500';
      bgColor = 'bg-rose-500/20';
      if (absScore > 70) strength = 'FORTE';
      else if (absScore > 35) strength = 'MODERADO';
    }

    return { direction, strength, color, bgColor, value: Math.round(absScore) };
  }, [breadthSummary, correlations, volumePressure, gap]);

  const handleManualAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, selectedAsset, correlations, events, "Strategic Analysis");
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const getBreadthLabel = () => {
    return selectedAsset.symbol === 'HK50' ? 'HSI Breadth' : 'Dow Breadth';
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden font-['Inter']">
      <header className="flex items-center justify-between px-6 py-3 bg-slate-900 border-b border-slate-800 shrink-0 shadow-2xl z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/30">
            <i className="fas fa-microchip text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-md font-extrabold tracking-tight uppercase leading-none">Sentinel Zone V3.8</h1>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-[9px] text-indigo-400 font-bold uppercase tracking-widest">NYSE: {nyTime}</span>
                <span className="flex items-center gap-1.5 px-2 py-0.5 bg-slate-800 rounded">
                    <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse-slow shadow-[0_0_5px_#10b981]"></span>
                    <span className="text-[9px] text-emerald-500 font-black uppercase tracking-widest">LIVE TRACKER</span>
                </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-5">
          <div className={`flex flex-col items-center px-6 py-2 rounded-xl border border-slate-700/60 shadow-lg ${sentimentScore.bgColor} transition-all duration-500 min-w-[160px]`}>
             <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.25em] mb-1">SENTIMENTO ATUAL</span>
             <div className={`flex items-center gap-3 ${sentimentScore.color}`}>
                <div className="flex flex-col items-center">
                    <span className="text-[14px] font-black jetbrains uppercase leading-none">{sentimentScore.direction}</span>
                    <span className="text-[10px] font-extrabold jetbrains opacity-80 mt-1">{sentimentScore.strength}</span>
                </div>
                <div className="w-px h-8 bg-slate-700/50 mx-1"></div>
                <span className="text-[18px] font-black jetbrains">{sentimentScore.value}%</span>
             </div>
          </div>

          <div className="flex items-center gap-2 bg-slate-800 border border-slate-700 rounded px-3 py-1.5">
             <i className="fas fa-globe text-[10px] text-slate-500"></i>
             <select value={utcOffset} onChange={(e) => setUtcOffset(parseInt(e.target.value))} className="bg-transparent text-white text-[10px] font-bold outline-none cursor-pointer jetbrains">
               {UTC_OFFSETS.map(o => <option key={o.value} value={o.value} className="bg-slate-900">{o.label}</option>)}
             </select>
          </div>
          <div className="flex bg-slate-800 p-1 rounded border border-slate-700">
            {TIMEFRAMES.map(tf => (
              <button key={tf.value} onClick={() => setTimeframe(tf.value)} className={`px-2.5 py-1 rounded text-[10px] font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}>
                {tf.label}
              </button>
            ))}
          </div>
          <select value={selectedAsset.symbol} onChange={(e) => {
              const asset = SUPPORTED_ASSETS.find(a => a.symbol === e.target.value)!;
              setSelectedAsset(asset);
              if (asset.symbol === 'HK50') setUtcOffset(8);
              else setUtcOffset(-5);
          }} className="bg-slate-800 border border-slate-700 text-white text-[11px] rounded p-2 font-bold outline-none hover:border-slate-600 transition-colors">
            {SUPPORTED_ASSETS.map(a => <option key={a.symbol} value={a.symbol}>{a.symbol} - {a.name}</option>)}
          </select>
          <button onClick={handleManualAnalysis} disabled={isAnalyzing} className="px-5 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-[11px] font-extrabold transition-all flex items-center gap-2 shadow-xl shadow-indigo-500/20 active:scale-95 disabled:opacity-50">
            {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-brain"></i>} AI ANALYSIS
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-64 border-r border-slate-800 bg-slate-900/40 flex flex-col shrink-0 p-4 overflow-y-auto space-y-6">
            <section>
                <div className="flex justify-between items-center mb-4 px-1">
                    <h3 className="text-[11px] font-extrabold text-slate-500 uppercase tracking-widest">Global Macro</h3>
                </div>
                <div className="space-y-3">
                    {correlations.map(c => (
                        <div key={c.symbol} className="flex items-center justify-between p-3 rounded-xl bg-[#1a1f2e] border border-slate-800/80 shadow-lg group hover:border-slate-700 transition-all">
                            <div className="flex flex-col">
                                <span className="text-[11px] font-black text-white uppercase leading-none mb-1.5 tracking-wider">{c.name}</span>
                                <span className={`text-[9px] font-black tracking-widest ${c.correlation === 'positive' ? 'text-indigo-400' : 'text-pink-400'}`}>
                                    {c.correlation === 'positive' ? 'DIRECT' : 'INVERSE'}
                                </span>
                            </div>
                            <div className={`text-[12px] font-black jetbrains ${c.change >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                                {c.change >= 0 ? '+' : ''}{c.change.toFixed(2)}%
                            </div>
                        </div>
                    ))}
                </div>
            </section>

            <section>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">Volume Momentum</h3>
                <div className="bg-slate-800 h-2.5 rounded-full overflow-hidden flex mb-3">
                    <div className="h-full bg-emerald-500 transition-all duration-700" style={{ width: `${volumePressure.buyPercent}%` }}></div>
                    <div className="h-full bg-rose-500 transition-all duration-700" style={{ width: `${volumePressure.sellPercent}%` }}></div>
                </div>
                <div className="flex justify-between text-[10px] font-black jetbrains">
                    <span className="text-emerald-500">BUY {volumePressure.buyPercent.toFixed(0)}%</span>
                    <span className="text-rose-500">SELL {volumePressure.sellPercent.toFixed(0)}%</span>
                </div>
            </section>

            <section>
                <div className="flex justify-between items-center mb-3">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{getBreadthLabel()}</h3>
                </div>
                <div className="bg-slate-900/80 p-4 rounded-xl border border-slate-800/50 cursor-pointer hover:border-indigo-500/30 transition-all shadow-lg" onClick={() => setIsBreadthModalOpen(true)}>
                    <div className="flex justify-around items-center mb-4">
                        <div className="flex flex-col items-center">
                            <span className="text-[10px] font-bold text-slate-500 mb-1">UP</span>
                            <span className="text-xl font-black text-emerald-500 jetbrains">{breadthSummary.advancing}</span>
                        </div>
                        <div className="flex flex-col items-center">
                            <span className="text-[10px] font-bold text-slate-500 mb-1">DOWN</span>
                            <span className="text-xl font-black text-rose-500 jetbrains">{breadthSummary.declining}</span>
                        </div>
                    </div>
                </div>
            </section>
        </aside>

        <div className="flex-1 flex flex-col relative p-2 overflow-hidden bg-slate-950">
          <div className="flex-1 bg-slate-900 rounded-2xl border border-slate-800 relative overflow-hidden shadow-2xl">
            <TradingChart candles={candles} asset={selectedAsset} utcOffset={utcOffset} gap={gap} zones={smcZones} loading={loading} />
          </div>

          <div className="grid grid-cols-4 gap-3 mt-3">
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex flex-col justify-center shadow-lg">
              <span className="text-[10px] text-slate-500 font-black uppercase block mb-1 tracking-widest">Market Status</span>
              <div className="flex items-center gap-2">
                <div className={`w-2.5 h-2.5 rounded-full ${candles.length > 0 ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-rose-500 animate-pulse'}`}></div>
                <span className="text-xs font-black uppercase tracking-widest">{candles.length > 0 ? 'CONNECTED' : 'STANDBY'}</span>
              </div>
            </div>

            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
              <span className="text-[10px] text-indigo-500 font-black uppercase block mb-1 tracking-widest">Opening Gap</span>
              <div className="flex items-baseline gap-2">
                <span className={`text-lg font-black jetbrains ${gap.type === 'up' ? 'text-emerald-500' : gap.type === 'down' ? 'text-rose-500' : 'text-slate-400'}`}>
                  {gap.percent.toFixed(2)}%
                </span>
              </div>
            </div>
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
              <span className="text-[10px] text-slate-500 font-black uppercase block mb-1 tracking-widest">Price Point</span>
              <span className="text-lg font-black text-indigo-400 jetbrains">
                {candles.length > 0 ? candles[candles.length - 1].close.toFixed(selectedAsset.decimals) : '0.00'}
              </span>
            </div>
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
              <span className="text-[10px] text-slate-500 font-black uppercase block mb-1 tracking-widest">Latency</span>
              <span className="text-lg font-black jetbrains text-slate-300">{latency}</span>
            </div>
          </div>
        </div>

        <aside className="w-80 border-l border-slate-800 bg-slate-900/60 flex flex-col shrink-0 overflow-hidden">
           <div className="p-4 border-b border-slate-800 bg-slate-900/80">
                <h2 className="text-[11px] font-black uppercase tracking-widest text-slate-300 mb-4 flex items-center gap-2">
                    <i className="fas fa-calendar-alt text-indigo-500"></i> High Impact Events
                </h2>
                <div className="space-y-3">
                    {events.map(event => (
                        <div key={event.id} className="p-3 rounded-lg bg-slate-800/40 border border-slate-700/50 hover:bg-slate-800 transition-colors">
                            <h4 className="text-[11px] font-extrabold text-slate-200 mb-1">{event.title}</h4>
                            <p className="text-[10px] text-slate-500 leading-relaxed">{event.description}</p>
                        </div>
                    ))}
                </div>
           </div>

           <div className="flex-1 flex flex-col overflow-hidden bg-slate-900/20">
                <div className="p-4 border-b border-slate-800">
                    <h2 className="text-[11px] font-black uppercase tracking-wider text-slate-300 flex items-center gap-2">
                        <i className="fas fa-brain text-indigo-500"></i> AI Intelligence Node
                    </h2>
                </div>
                <div className="flex-1 p-4 overflow-y-auto">
                    {!aiAnalysis ? (
                        <div className="flex flex-col items-center justify-center h-full text-center opacity-30">
                            <i className="fas fa-satellite text-4xl mb-4 text-slate-700"></i>
                            <p className="text-[10px] font-black uppercase tracking-wide">Select asset and execute analysis.</p>
                        </div>
                    ) : (
                        <div className="prose prose-invert prose-sm">
                            {aiAnalysis.split('\n').map((line, i) => (
                                line.trim() && <div key={i} className="mb-4 bg-indigo-500/5 p-4 rounded-xl border border-indigo-500/10 text-[11px] text-slate-300 border-l-4 border-l-indigo-500 shadow-md jetbrains leading-relaxed">
                                    {line}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
           </div>
        </aside>
      </main>

      <footer className="px-6 py-2 bg-slate-950 border-t border-slate-800 flex items-center justify-between text-[10px] font-black uppercase text-slate-600">
        <div className="flex items-center gap-8">
          <span className="flex items-center gap-2"><i className="fas fa-shield-alt text-indigo-500"></i> NODE SECURE</span>
          <span className="flex items-center gap-2">INDEX MONITOR: {selectedAsset.symbol} | {selectedAsset.name}</span>
        </div>
        <span>SENTINEL ZONE PRO V3.8.3 (REAL-TIME ENGINE)</span>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time, CrosshairMode } from 'lightweight-charts';
import { Candle, Asset, GapData, SMCZone } from '../types';

interface Props {
  candles: Candle[];
  asset: Asset;
  utcOffset: number;
  gap: GapData;
  zones: SMCZone[];
  loading: boolean;
}

const TradingChart: React.FC<Props> = ({ candles, asset, utcOffset, gap, zones, loading }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);
  const initialLoadRef = useRef(true);
  const lastTimeRef = useRef<number>(0);

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    initialLoadRef.current = true;
    lastTimeRef.current = 0;
  }, [asset.symbol]);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#020617' },
        textColor: '#94a3b8',
        fontSize: 12,
        fontFamily: 'Inter, sans-serif',
      },
      grid: {
        vertLines: { color: 'rgba(15, 23, 42, 0.5)' },
        horzLines: { color: 'rgba(15, 23, 42, 0.5)' },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
        vertLine: { 
          color: '#6366f1', 
          labelBackgroundColor: '#6366f1', 
          width: 1, 
          style: 3 
        },
        horzLine: { 
          color: '#6366f1', 
          labelBackgroundColor: '#6366f1', 
          width: 1, 
          style: 3 
        },
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
        secondsVisible: false,
        shiftVisibleRangeOnNewBar: true,
        rightOffset: 12,
        barSpacing: 6,
      },
      rightPriceScale: {
        borderColor: '#1e293b',
        autoScale: true,
        alignLabels: true,
        borderVisible: true,
        scaleMargins: {
          top: 0.1,
          bottom: 0.1,
        },
      },
      handleScroll: {
        mouseWheel: true,
        pressedMouseMove: true,
        horzTouchDrag: true,
        vertTouchDrag: true,
      },
      handleScale: {
        axisPressedMouseMove: {
          time: true,
          price: true,
        },
        mouseWheel: true,
        pinch: true,
      },
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    const handleResize = () => {
      if (chartContainerRef.current && chartRef.current) {
        chartRef.current.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };

    window.addEventListener('resize', handleResize);

    const drawOverlays = () => {
      if (!canvasRef.current || !chartRef.current || !seriesRef.current || candles.length === 0) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const canvas = canvasRef.current;
      const currentWidth = chartContainerRef.current?.clientWidth || 0;
      const currentHeight = chartContainerRef.current?.clientHeight || 0;

      if (canvas.width !== currentWidth || canvas.height !== currentHeight) {
        canvas.width = currentWidth;
        canvas.height = currentHeight;
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const timeScale = chartRef.current.timeScale();
      const priceScale = seriesRef.current;

      if (gap.type !== 'none' && gap.startIndex !== undefined && gap.prevClose && gap.openPrice) {
        const firstCandleTime = (candles[gap.startIndex].time + offsetInSeconds) as Time;
        const xGap = timeScale.timeToCoordinate(firstCandleTime);
        const pg1 = priceScale.priceToCoordinate(gap.prevClose);
        const pg2 = priceScale.priceToCoordinate(gap.openPrice);

        if (xGap !== null && pg1 !== null && pg2 !== null) {
          ctx.fillStyle = gap.type === 'up' ? 'rgba(16, 185, 129, 0.03)' : 'rgba(239, 68, 68, 0.03)';
          ctx.fillRect(xGap - 40, Math.min(pg1, pg2), canvas.width - xGap + 40, Math.abs(pg1 - pg2));
          ctx.strokeStyle = gap.type === 'up' ? 'rgba(16, 185, 129, 0.2)' : 'rgba(239, 68, 68, 0.2)';
          ctx.setLineDash([5, 5]);
          ctx.beginPath();
          ctx.moveTo(xGap - 50, pg1);
          ctx.lineTo(canvas.width, pg1);
          ctx.stroke();
          ctx.setLineDash([]);
        }
      }
    };

    const interval = setInterval(drawOverlays, 100);
    chart.timeScale().subscribeVisibleTimeRangeChange(drawOverlays);

    return () => {
      window.removeEventListener('resize', handleResize);
      clearInterval(interval);
      chart.remove();
    };
  }, [asset.symbol, offsetInSeconds]);

  // Atualização de Dados Otimizada (Incremental)
  useEffect(() => {
    if (seriesRef.current && chartRef.current) {
      if (candles.length === 0) {
        seriesRef.current.setData([]);
        lastTimeRef.current = 0;
        return;
      }

      const lastCandle = candles[candles.length - 1];
      const formattedLast = {
        time: (lastCandle.time + offsetInSeconds) as Time,
        open: lastCandle.open,
        high: lastCandle.high,
        low: lastCandle.low,
        close: lastCandle.close,
      };

      // Se o tamanho mudou ou é a primeira carga, reseta tudo
      if (initialLoadRef.current || candles.length !== lastTimeRef.current) {
        const formattedData = candles.map(c => ({
          time: (c.time + offsetInSeconds) as Time,
          open: c.open,
          high: c.high,
          low: c.low,
          close: c.close,
        }));
        seriesRef.current.setData(formattedData);

        if (initialLoadRef.current) {
          chartRef.current.timeScale().fitContent();
          initialLoadRef.current = false;
        }
        lastTimeRef.current = candles.length;
      } else {
        // Atualização via 'update' para o último tick (mais suave)
        seriesRef.current.update(formattedLast);
      }
    }
  }, [candles, offsetInSeconds]);

  return (
    <div className="relative w-full h-full bg-[#020617] cursor-crosshair">
        <div ref={chartContainerRef} className="w-full h-full" />
        <canvas ref={canvasRef} className="absolute top-0 left-0 pointer-events-none w-full h-full z-10" />

        {(loading || !isReady) && (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-950/80 backdrop-blur-sm z-50">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[11px] font-black text-indigo-400 uppercase tracking-widest animate-pulse">Sincronizando Fluxo Live</span>
                </div>
            </div>
        )}

        <div className="absolute top-4 left-4 z-20 pointer-events-none opacity-40 hover:opacity-100 transition-opacity">
           <div className="bg-slate-900/80 px-3 py-1.5 rounded-md border border-slate-800 text-[9px] font-bold text-slate-500 flex items-center gap-3">
              <span><i className="fas fa-mouse mr-1"></i> SCROLL TO ZOOM</span>
              <span><i className="fas fa-arrows-alt mr-1"></i> DRAG TO PAN</span>
           </div>
        </div>
    </div>
  );
};

