  const loadData = useCallback(async (isInitialLoad = false) => {
    if (isInitialLoad) setLoading(true);

    try {
      const start = Date.now();
      const [candleData, corrData, breadthRes, eventData] = await Promise.all([
        fetchRealData(selectedAsset, timeframe),
        fetchCorrelationData(selectedAsset.symbol),
        fetchMarketBreadth(selectedAsset.symbol),
        fetchEconomicEvents()
      ]);

      setLatency(`${Date.now() - start}ms`);
      setCorrelations(corrData);
      setBreadthSummary(breadthRes.summary);
      setEvents(eventData);
      setLastSync(0);

      if (candleData.length > 0) {
        const latestReal = candleData[candleData.length - 1].close;
        lastRealPriceRef.current = latestReal;

        // --- LOGICA DE TEMPO REAL: PREENCHIMENTO DE GAP ---
        const nowUnix = Math.floor(Date.now() / 1000);
        const tfSeconds = TIMEFRAMES.find(t => t.value === timeframe)?.seconds || 60;
        let lastTime = candleData[candleData.length - 1].time;
        const augmentedCandles = [...candleData];

        // Se o dado da API estiver atrasado em relação ao relógio local, criamos velas de preenchimento
        while (lastTime + tfSeconds <= nowUnix) {
          lastTime += tfSeconds;
          const fillerCandle: Candle = {
            time: lastTime,
            open: augmentedCandles[augmentedCandles.length - 1].close,
            high: augmentedCandles[augmentedCandles.length - 1].close,
            low: augmentedCandles[augmentedCandles.length - 1].close,
            close: augmentedCandles[augmentedCandles.length - 1].close,
            volume: 0
          };
          augmentedCandles.push(fillerCandle);
        }

        setCandles(augmentedCandles);
        setVolumePressure(calculateVolumePressure(augmentedCandles));
        setGap(detectOpeningGap(augmentedCandles, selectedAsset));
      }
    } catch (err) {
      console.error("Critical Sync Error:", err);
    } finally {
      if (isInitialLoad) setLoading(false);
    }
  }, [selectedAsset, timeframe]);

  // Polling de 10s para manter os dados macro atualizados
  useEffect(() => {
    loadData(true);
    const interval = setInterval(() => loadData(false), 10000);
    return () => clearInterval(interval);
  }, [selectedAsset, timeframe, loadData]);

  // Tick Engine de Alta Frequência (250ms) - Garante que o gráfico nunca pare
  useEffect(() => {
    if (candles.length === 0 || loading) return;

    const tfSeconds = TIMEFRAMES.find(t => t.value === timeframe)?.seconds || 60;

    const tickInterval = setInterval(() => {
      setCandles(prev => {
        if (prev.length === 0) return prev;
        const last = prev[prev.length - 1];
        const nowUnix = Math.floor(Date.now() / 1000);

        // Inicia nova vela se o tempo da barra atual expirou
        if (nowUnix >= last.time + tfSeconds) {
          const newCandle: Candle = {
            time: last.time + tfSeconds,
            open: last.close,
            high: last.close,
            low: last.close,
            close: last.close,
            volume: 0
          };
          return [...prev, newCandle];
        }

        // Simula variação de preço (Tick Movement)
        const volatility = last.close * 0.00003;
        const drift = lastRealPriceRef.current ? (lastRealPriceRef.current - last.close) * 0.05 : 0;
        const change = ((Math.random() - 0.5) * volatility) + drift;
        const newClose = last.close + change;

        const updatedLast = {
          ...last,
          close: newClose,
          high: Math.max(last.high, newClose),
          low: Math.min(last.low, newClose)
        };
        return [...prev.slice(0, -1), updatedLast];
      });
    }, 250);

    return () => clearInterval(tickInterval);
  }, [candles.length, loading, timeframe]);

  const smcZones = useMemo(() => {
