    else if (advRatio < 0.4) direction = 'VENDA';
    return { direction, value: Math.round(advRatio * 100) };
  }, [breadthSummary]);

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden font-['Inter']">
      <header className="flex items-center justify-between px-6 py-3 bg-slate-900 border-b border-slate-800 shrink-0 shadow-2xl z-20">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/30">
            <i className="fas fa-satellite-dish text-white text-xl animate-pulse"></i>
          </div>
          <div>
            <h1 className="text-md font-extrabold tracking-tight uppercase leading-none">Sentinel Zone PRO</h1>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-[9px] text-indigo-400 font-bold uppercase tracking-widest">NYSE: {nyTime}</span>
                <span className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-500/10 rounded">
                    <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse-slow"></span>
                    <span className="text-[9px] text-emerald-500 font-black uppercase tracking-widest">LIVE ENGINE ACTIVE</span>
                </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-5">
          <div className="flex items-center gap-4 bg-slate-800/50 p-1.5 rounded-xl border border-slate-700/50">
             <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-500 uppercase">Sentiment</span>
                <span className={`text-[12px] font-black jetbrains ${sentimentScore.direction === 'COMPRA' ? 'text-emerald-500' : 'text-rose-500'}`}>{sentimentScore.direction}</span>
             </div>
             <div className="w-px h-8 bg-slate-700"></div>
             <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-500 uppercase">Flow</span>
                <span className="text-[12px] font-black text-indigo-400 jetbrains">{sentimentScore.value}%</span>
             </div>
