import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time, CrosshairMode } from 'lightweight-charts';
import { Candle, Asset, GapData, SMCZone } from '../types';

interface Props {
  candles: Candle[];
  asset: Asset;
  utcOffset: number;
  gap: GapData;
  zones: SMCZone[];
  loading: boolean;
}

const TradingChart: React.FC<Props> = ({ candles, asset, utcOffset, gap, zones, loading }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);
  const initialLoadRef = useRef(true);
  const lastTimeRef = useRef<number>(0);
  const isAutoScrollingRef = useRef(true);

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    initialLoadRef.current = true;
    lastTimeRef.current = 0;
  }, [asset.symbol]);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#0f172a' },
        textColor: '#64748b',
        fontSize: 11,
        fontFamily: 'Inter, sans-serif',
      },
      grid: {
        vertLines: { color: 'rgba(30, 41, 59, 0.5)' },
        horzLines: { color: 'rgba(30, 41, 59, 0.5)' },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
        vertLine: { color: '#6366f1', labelBackgroundColor: '#6366f1', style: 3 },
        horzLine: { color: '#6366f1', labelBackgroundColor: '#6366f1', style: 3 },
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
        secondsVisible: true, // Mostra segundos para o sentimento de tempo real
        rightOffset: 15,
        barSpacing: 8,
        shiftVisibleRangeOnNewBar: true,
      },
      rightPriceScale: {
        borderColor: '#1e293b',
        autoScale: true,
        scaleMargins: { top: 0.15, bottom: 0.15 },
      },
      handleScroll: { mouseWheel: true, pressedMouseMove: true },
      handleScale: { axisPressedMouseMove: true, mouseWheel: true },
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    // Detecta se o usuário parou o auto-scroll ao arrastar o gráfico
    chart.timeScale().subscribeVisibleTimeRangeChange(() => {
      const timeScale = chart.timeScale();
      const visibleRange = timeScale.getVisibleRange();
      if (!visibleRange) return;
      // Se estiver muito longe do final, desativa auto-scroll
      // isAutoScrollingRef.current = (alguma lógica opcional)
    });

    const handleResize = () => {
      if (chartContainerRef.current && chartRef.current) {
        chartRef.current.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      chart.remove();
    };
  }, [asset.symbol, offsetInSeconds]);

  // Atualização em Tempo Real (Tick by Tick)
  useEffect(() => {
    if (seriesRef.current && chartRef.current && candles.length > 0) {
      const lastCandle = candles[candles.length - 1];
      const formattedLast = {
        time: (lastCandle.time + offsetInSeconds) as Time,
        open: lastCandle.open,
        high: lastCandle.high,
        low: lastCandle.low,
        close: lastCandle.close,
      };

      if (initialLoadRef.current || candles.length !== lastTimeRef.current) {
        const formattedData = candles.map(c => ({
          time: (c.time + offsetInSeconds) as Time,
          open: c.open,
          high: c.high,
          low: c.low,
          close: c.close,
        }));
        seriesRef.current.setData(formattedData);

        if (initialLoadRef.current) {
          chartRef.current.timeScale().fitContent();
          initialLoadRef.current = false;
        }
        lastTimeRef.current = candles.length;
      } else {
        // Envia o tick individual para o gráfico de forma fluida
        seriesRef.current.update(formattedLast);
      }
    }
  }, [candles, offsetInSeconds]);

  return (
    <div className="relative w-full h-full bg-[#0f172a]">
        <div ref={chartContainerRef} className="w-full h-full" />

        {(loading || !isReady) && (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-950/90 backdrop-blur-md z-50">
                <div className="flex flex-col items-center gap-6">
                    <div className="relative w-16 h-16">
                      <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
                      <div className="absolute inset-0 border-4 border-t-indigo-500 rounded-full animate-spin"></div>
                    </div>
                    <div className="flex flex-col items-center gap-1">
                        <span className="text-[12px] font-black text-indigo-400 uppercase tracking-[0.3em] animate-pulse">Sincronizando Mercado</span>
                        <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Aguardando dados da NYSE/HKEX</span>
                    </div>
                </div>
            </div>
        )}

        {/* Floating Price Tracker */}
        {isReady && candles.length > 0 && (
