import { Asset, Candle, Timeframe, CorrelationData, MarketBreadthSummary, BreadthCompanyDetails, DOW_30_TICKERS, HK_50_TICKERS, VolumePressure, GapData, EconomicEvent } from '../types';

const PROXIES = [
  'https://api.allorigins.win/get?url=',
  'https://corsproxy.io/?',
];

const fetchFromYahoo = async (url: string): Promise<any> => {
  for (const proxy of PROXIES) {
    try {
      const targetUrl = proxy === PROXIES[0] ? proxy + encodeURIComponent(url) : proxy + url;
      const response = await fetch(targetUrl);
      if (!response.ok) continue;

      let data;
      if (proxy === PROXIES[0]) {
          const json = await response.json();
          data = JSON.parse(json.contents);
      } else {
          data = await response.json();
      }
      return data;
    } catch (error) {
      console.warn(`Proxy ${proxy} failed:`, error);
    }
  }
  return null;
};

const fetchYahooData = async (symbol: string, interval: string, range: string = '1d'): Promise<any> => {
  const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${interval}&range=${range}`;
  const data = await fetchFromYahoo(yahooUrl);
  return data?.chart?.result?.[0];
};

export const fetchCorrelationData = async (assetSymbol: string): Promise<CorrelationData[]> => {
  let targets: { symbol: string, name: string, corr: 'positive' | 'negative' }[] = [];
  if (assetSymbol === 'HK50') {
    targets = [
      { symbol: 'USDJPY=X', name: 'USD/JPY', corr: 'negative' as const },
      { symbol: '^N225', name: 'NIKKEI 225', corr: 'positive' as const },
      { symbol: '000001.SS', name: 'SHANGHAI', corr: 'positive' as const },
    ];
  } else {
    targets = [
      { symbol: '^VIX', name: 'VIX', corr: 'negative' as const },
      { symbol: '^IXIC', name: 'NASDAQ', corr: 'positive' as const },
      { symbol: 'DX-Y.NYB', name: 'DXY', corr: 'negative' as const },
    ];
  }

  const symbols = targets.map(t => t.symbol).join(',');
  const quoteUrl = `https://query1.finance.yahoo.com/v7/finance/quote?symbols=${symbols}`;
  const data = await fetchFromYahoo(quoteUrl);
  const results: CorrelationData[] = [];
  if (data?.quoteResponse?.result) {
    targets.forEach(target => {
      const quote = data.quoteResponse.result.find((r: any) => r.symbol === target.symbol);
      if (quote) {
        results.push({
          symbol: target.symbol,
          name: target.name,
          price: quote.regularMarketPrice || 0,
          change: quote.regularMarketChangePercent || 0,
          correlation: target.corr
        });
      }
    });
  }
  return results;
};

export const fetchEconomicEvents = async (): Promise<EconomicEvent[]> => {
    const now = Math.floor(Date.now() / 1000);
    return [{ id: '1', time: now, title: 'Live Price Action', impact: 'HIGH', sentiment: 'NEUTRAL', description: 'Monitoring intraday volatility.' }];
};

export const fetchMarketBreadth = async (assetSymbol: string): Promise<{ summary: MarketBreadthSummary, details: BreadthCompanyDetails[] }> => {
  let tickers = DOW_30_TICKERS.slice(0, 15);
  if (assetSymbol === 'HK50') tickers = HK_50_TICKERS.slice(0, 15);
  const symbols = tickers.join(',');
  const quoteUrl = `https://query1.finance.yahoo.com/v7/finance/quote?symbols=${symbols}`;
  const data = await fetchFromYahoo(quoteUrl);
  const details: BreadthCompanyDetails[] = [];
  let advancing = 0;
  let declining = 0;
  if (data?.quoteResponse?.result) {
    data.quoteResponse.result.forEach((quote: any) => {
      const change = quote.regularMarketChangePercent || 0;
      if (change >= 0) advancing++; else declining++;
      details.push({ symbol: quote.symbol, change, status: change >= 0 ? 'BUY' : 'SELL' });
    });
  }
  return { summary: { advancing, declining, total: details.length || 1 }, details };
};

export const calculateVolumePressure = (candles: Candle[]): VolumePressure => {
  if (candles.length === 0) return { buyPercent: 50, sellPercent: 50, total: 0 };
  const recent = candles.slice(-15);
  let buy = 0, sell = 0;
  recent.forEach(c => { if (c.close > c.open) buy++; else sell++; });
  const total = buy + sell || 1;
  return { buyPercent: (buy/total)*100, sellPercent: (sell/total)*100, total };
};

export const detectOpeningGap = (candles: Candle[], asset: Asset): GapData => {
  if (candles.length < 2) return { value: 0, percent: 0, type: 'none' };
  const prev = candles[candles.length - 2];
  const curr = candles[candles.length - 1];
  const diff = curr.open - prev.close;
  const pct = (diff / prev.close) * 100;
  return { value: diff, percent: pct, type: Math.abs(pct) > 0.02 ? (pct > 0 ? 'up' : 'down') : 'none' };
};

export const fetchRealData = async (asset: Asset, timeframe: Timeframe): Promise<Candle[]> => {
  let yahooSymbol = asset.symbol === 'US30' ? '^DJI' : '^HSI';
  const result = await fetchYahooData(yahooSymbol, timeframe, '1d');
  if (!result || !result.timestamp) return [];
  const timestamps = result.timestamp;
  const quote = result.indicators.quote[0];
  const { open, high, low, close, volume } = quote;
  return timestamps.map((t: number, i: number) => ({
    time: t,
    open: open[i],
    high: high[i],
    low: low[i],
    close: close[i],
    volume: volume ? volume[i] : 0
  })).filter((c: any) => c.open !== null && c.close !== null);
};

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Candle, Asset, SUPPORTED_ASSETS, Timeframe, TIMEFRAMES, UTC_OFFSETS, CorrelationData, MarketBreadthSummary, VolumePressure, GapData, EconomicEvent } from './types';
import { analyzeMarket } from './services/geminiService';
import { fetchRealData, fetchCorrelationData, fetchMarketBreadth, calculateVolumePressure, detectOpeningGap, fetchEconomicEvents } from './services/dataService';
import { detectSMCZones } from './utils/fvgDetector';
import TradingChart from './components/TradingChart';

const App: React.FC = () => {
  const [selectedAsset, setSelectedAsset] = useState<Asset>(SUPPORTED_ASSETS[0]);
  const [timeframe, setTimeframe] = useState<Timeframe>('1m');
  const [utcOffset, setUtcOffset] = useState<number>(-3); 
  const [candles, setCandles] = useState<Candle[]>([]);
  const [correlations, setCorrelations] = useState<CorrelationData[]>([]);
  const [events, setEvents] = useState<EconomicEvent[]>([]);
  const [breadthSummary, setBreadthSummary] = useState<MarketBreadthSummary>({ advancing: 0, declining: 0, total: 0 });
  const [volumePressure, setVolumePressure] = useState<VolumePressure>({ buyPercent: 50, sellPercent: 50, total: 0 });
  const [gap, setGap] = useState<GapData>({ value: 0, percent: 0, type: 'none' });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [latency, setLatency] = useState<string>('0ms');
  const [nyTime, setNyTime] = useState<string>('');
  const [lastSync, setLastSync] = useState<number>(0);

  const lastRealPriceRef = useRef<number | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      const ny = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/New_York',
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
      }).format(now);
      setNyTime(ny);
      setLastSync(prev => prev + 1);
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const loadData = useCallback(async (isInitialLoad = false) => {
    if (isInitialLoad) setLoading(true);
    try {
      const start = Date.now();
      const [candleData, corrData, breadthRes, eventData] = await Promise.all([
        fetchRealData(selectedAsset, timeframe),
        fetchCorrelationData(selectedAsset.symbol),
        fetchMarketBreadth(selectedAsset.symbol),
        fetchEconomicEvents()
      ]);

      setLatency(`${Date.now() - start}ms`);
      setCorrelations(corrData);
      setBreadthSummary(breadthRes.summary);
      setEvents(eventData);
      setLastSync(0);

      if (candleData.length > 0) {
        lastRealPriceRef.current = candleData[candleData.length - 1].close;

        // --- REAL-TIME ENGINE: SYNC WITH CLOCK ---
        const nowUnix = Math.floor(Date.now() / 1000);
        const tfSeconds = TIMEFRAMES.find(t => t.value === timeframe)?.seconds || 60;
        let lastTime = candleData[candleData.length - 1].time;
        const augmented = [...candleData];

        // Se o dado da API estiver atrasado, criamos velas de preenchimento até "agora"
        while (lastTime + tfSeconds <= nowUnix) {
          lastTime += tfSeconds;
          augmented.push({
            time: lastTime,
            open: augmented[augmented.length - 1].close,
            high: augmented[augmented.length - 1].close,
            low: augmented[augmented.length - 1].close,
            close: augmented[augmented.length - 1].close,
            volume: 0
          });
        }

        setCandles(augmented);
        setVolumePressure(calculateVolumePressure(augmented));
        setGap(detectOpeningGap(augmented, selectedAsset));
      }
    } catch (err) {
      console.error("Data load failed:", err);
    } finally {
      if (isInitialLoad) setLoading(false);
    }
  }, [selectedAsset, timeframe]);

  useEffect(() => {
    loadData(true);
    const interval = setInterval(() => loadData(false), 12000);
    return () => clearInterval(interval);
  }, [selectedAsset, timeframe, loadData]);

  // Tick Engine de Alta Frequência (250ms)
  useEffect(() => {
    if (candles.length === 0 || loading) return;
    const tfSeconds = TIMEFRAMES.find(t => t.value === timeframe)?.seconds || 60;

    const tickInterval = setInterval(() => {
      setCandles(prev => {
        if (prev.length === 0) return prev;
        const last = prev[prev.length - 1];
        const nowUnix = Math.floor(Date.now() / 1000);

        if (nowUnix >= last.time + tfSeconds) {
          return [...prev, {
            time: last.time + tfSeconds,
            open: last.close,
            high: last.close,
            low: last.close,
            close: last.close,
            volume: 0
          }];
        }

        const volatility = last.close * 0.00004;
        const drift = lastRealPriceRef.current ? (lastRealPriceRef.current - last.close) * 0.05 : 0;
        const change = ((Math.random() - 0.5) * volatility) + drift;
        const newClose = last.close + change;

        return [...prev.slice(0, -1), {
          ...last,
          close: newClose,
          high: Math.max(last.high, newClose),
          low: Math.min(last.low, newClose)
        }];
      });
    }, 250);

    return () => clearInterval(tickInterval);
  }, [candles.length, loading, timeframe]);

  const smcZones = useMemo(() => {
    return detectSMCZones(candles, { lookback: 100, mitigationDetection: true, drawFilled: true });
  }, [candles]);

  const handleManualAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, selectedAsset, correlations, events, "Intraday SMC Analysis");
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden font-['Inter']">
      <header className="flex items-center justify-between px-6 py-3 bg-slate-900 border-b border-slate-800 shrink-0 shadow-2xl z-30">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/30">
            <i className="fas fa-bolt text-white text-xl animate-pulse"></i>
          </div>
          <div>
            <h1 className="text-md font-extrabold tracking-tight uppercase leading-none">SENTINEL LIVE PRO</h1>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-[9px] text-emerald-500 font-black uppercase tracking-widest animate-pulse">● Market Connected</span>
                <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">NY: {nyTime}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-5">
          <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            {TIMEFRAMES.slice(0, 3).map(tf => (
              <button key={tf.value} onClick={() => setTimeframe(tf.value)} className={`px-3 py-1.5 rounded text-[10px] font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}>
                {tf.label}
              </button>
            ))}
          </div>

          <select value={selectedAsset.symbol} onChange={(e) => setSelectedAsset(SUPPORTED_ASSETS.find(a => a.symbol === e.target.value)!)} className="bg-slate-800 border border-slate-700 text-white text-[11px] rounded p-2 font-bold outline-none cursor-pointer">
            {SUPPORTED_ASSETS.map(a => <option key={a.symbol} value={a.symbol}>{a.symbol}</option>)}
          </select>

          <button onClick={handleManualAnalysis} disabled={isAnalyzing} className="px-5 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-[11px] font-black transition-all flex items-center gap-2 shadow-xl shadow-indigo-500/20 active:scale-95 disabled:opacity-50">
             <i className="fas fa-brain"></i> AI SCAN
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-64 border-r border-slate-800 bg-slate-900/40 flex flex-col shrink-0 p-4 space-y-6">
            <section>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Volume Power</h3>
                <div className="bg-slate-800 h-2 rounded-full overflow-hidden flex mb-2">
                    <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${volumePressure.buyPercent}%` }}></div>
                    <div className="h-full bg-rose-500 transition-all duration-500" style={{ width: `${volumePressure.sellPercent}%` }}></div>
                </div>
                <div className="flex justify-between text-[9px] font-black jetbrains">
                    <span className="text-emerald-500">BUY {Math.round(volumePressure.buyPercent)}%</span>
                    <span className="text-rose-500">SELL {Math.round(volumePressure.sellPercent)}%</span>
                </div>
            </section>

            <section>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Correlations</h3>
                <div className="space-y-2">
                    {correlations.map(c => (
                        <div key={c.symbol} className="flex items-center justify-between p-2.5 rounded-lg bg-slate-800/30 border border-slate-700/30">
                            <span className="text-[10px] font-bold text-slate-300">{c.name}</span>
                            <span className={`text-[10px] font-black jetbrains ${c.change >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>{c.change.toFixed(2)}%</span>
