      const start = Date.now();
      const [candleData, corrData, breadthRes, eventData] = await Promise.all([
        fetchRealData(selectedAsset, timeframe),
        fetchCorrelationData(selectedAsset.symbol),
        fetchMarketBreadth(selectedAsset.symbol),
        fetchEconomicEvents()
      ]);

      setLatency(`${Date.now() - start}ms`);
      setCorrelations(corrData);
      setBreadthSummary(breadthRes.summary);
      setEvents(eventData);
      setCandles(candleData);

      if (candleData.length > 0) {
        setVolumePressure(calculateVolumePressure(candleData));
        setGap(detectOpeningGap(candleData, selectedAsset));
      }
    } catch (err) {
      console.error("Data load failed:", err);
    } finally {
      if (isInitialLoad) setLoading(false);
    }
  }, [selectedAsset, timeframe]);

  useEffect(() => {
    loadData(true);
    const interval = setInterval(() => loadData(false), 30000);
    return () => clearInterval(interval);
  }, [selectedAsset, timeframe, loadData]);

  const smcZones = useMemo(() => {
    return detectSMCZones(candles, { lookback: 200, mitigationDetection: true, drawFilled: true });
  }, [candles]);

  const handleManualAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeMarket(candles, selectedAsset, correlations, events, "Standard SMC Technical Analysis");
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden font-['Inter']">
      <header className="flex items-center justify-between px-6 py-3 bg-slate-900 border-b border-slate-800 shrink-0 shadow-2xl z-30">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/30">
            <i className="fas fa-chart-line text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-md font-extrabold tracking-tight uppercase leading-none">SENTINEL ZONE PRO</h1>
            <div className="flex items-center gap-2 mt-1">
                <span className="text-[9px] text-indigo-400 font-black uppercase tracking-widest">SMC & FVG Analyzer</span>
                <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">NY: {nyTime}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-5">
          <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            {TIMEFRAMES.map(tf => (
              <button key={tf.value} onClick={() => setTimeframe(tf.value)} className={`px-3 py-1.5 rounded text-[10px] font-bold transition-all ${timeframe === tf.value ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}>
                {tf.label}
              </button>
            ))}
          </div>

          <select value={selectedAsset.symbol} onChange={(e) => setSelectedAsset(SUPPORTED_ASSETS.find(a => a.symbol === e.target.value)!)} className="bg-slate-800 border border-slate-700 text-white text-[11px] rounded p-2 font-bold outline-none cursor-pointer">
            {SUPPORTED_ASSETS.map(a => <option key={a.symbol} value={a.symbol}>{a.symbol}</option>)}
          </select>

          <button onClick={handleManualAnalysis} disabled={isAnalyzing} className="px-5 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-[11px] font-black transition-all flex items-center gap-2 shadow-xl shadow-indigo-500/20 active:scale-95 disabled:opacity-50">
             <i className="fas fa-brain"></i> AI SCAN
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-64 border-r border-slate-800 bg-slate-900/40 flex flex-col shrink-0 p-4 space-y-6">
            <section>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Volume Pressure</h3>
                <div className="bg-slate-800 h-2 rounded-full overflow-hidden flex mb-2">
                    <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${volumePressure.buyPercent}%` }}></div>
                    <div className="h-full bg-rose-500 transition-all duration-500" style={{ width: `${volumePressure.sellPercent}%` }}></div>
                </div>
                <div className="flex justify-between text-[9px] font-black jetbrains">
                    <span className="text-emerald-500">BUY {Math.round(volumePressure.buyPercent)}%</span>
                    <span className="text-rose-500">SELL {Math.round(volumePressure.sellPercent)}%</span>
                </div>
            </section>

            <section className="flex-1 overflow-y-auto">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Market Context</h3>
                <div className="space-y-3">
                    {correlations.map(c => (
                        <div key={c.symbol} className="p-3 rounded-lg bg-slate-800/30 border border-slate-700/30">
                            <div className="flex items-center justify-between mb-1">
                                <span className="text-[10px] font-bold text-slate-300">{c.name}</span>
                                <span className={`text-[10px] font-black jetbrains ${c.change >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>{c.change.toFixed(2)}%</span>
                            </div>
                            <div className="text-[9px] text-slate-500 uppercase font-black tracking-tighter">
                                {c.correlation === 'positive' ? 'Direct Corr.' : 'Inverse Corr.'}
                            </div>
                        </div>
                    ))}
                </div>
            </section>

            {aiAnalysis && (
                <section className="p-3 bg-indigo-600/10 border border-indigo-500/30 rounded-xl overflow-y-auto max-h-48">
                    <h4 className="text-[10px] font-black text-indigo-400 uppercase mb-2">AI Insights</h4>
                    <p className="text-[10px] leading-relaxed text-slate-300 whitespace-pre-wrap">{aiAnalysis}</p>
                </section>
            )}
        </aside>

        <div className="flex-1 flex flex-col p-2 bg-slate-950">
          <div className="flex-1 bg-slate-900 rounded-2xl border border-slate-800 relative overflow-hidden shadow-2xl">
            <TradingChart candles={candles} asset={selectedAsset} utcOffset={utcOffset} gap={gap} zones={smcZones} loading={loading} />
          </div>

          <div className="grid grid-cols-4 gap-3 mt-3">
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
                <span className="text-[9px] text-slate-500 font-black uppercase mb-1 block">Latest Price</span>
                <span className="text-xl font-black jetbrains text-white">
                    {candles.length > 0 ? candles[candles.length - 1].close.toFixed(selectedAsset.decimals) : '---'}
                </span>
            </div>
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
                <span className="text-[9px] text-slate-500 font-black uppercase mb-1 block">API Latency</span>
                <span className="text-xl font-black jetbrains text-indigo-400">{latency}</span>
            </div>
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
                <span className="text-[9px] text-slate-500 font-black uppercase mb-1 block">Active Zones</span>
                <span className="text-xl font-black jetbrains text-emerald-400">{smcZones.filter(z => !z.mitigated).length}</span>
            </div>
            <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
                <span className="text-[9px] text-slate-500 font-black uppercase mb-1 block">Data Points</span>
                <span className="text-xl font-black jetbrains text-slate-300">{candles.length}</span>
            </div>
          </div>
        </div>
      </main>

      <footer className="px-6 py-2 bg-slate-900 border-t border-slate-800 flex justify-between text-[9px] font-black uppercase text-slate-600 tracking-widest z-30">
        <span>Sentinel Pro Dashboard</span>
        <span className="text-slate-500">Historical Analysis Mode</span>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { createChart, ColorType, IChartApi, ISeriesApi, Time, CrosshairMode } from 'lightweight-charts';
import { Candle, Asset, GapData, SMCZone } from '../types';

interface Props {
  candles: Candle[];
  asset: Asset;
  utcOffset: number;
  gap: GapData;
  zones: SMCZone[];
  loading: boolean;
}

const TradingChart: React.FC<Props> = ({ candles, asset, utcOffset, gap, zones, loading }) => {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const seriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const [isReady, setIsReady] = useState(false);
  const initialLoadRef = useRef(true);

  const offsetInSeconds = utcOffset * 3600;

  useEffect(() => {
    initialLoadRef.current = true;
  }, [asset.symbol]);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: '#0f172a' },
        textColor: '#64748b',
        fontSize: 11,
        fontFamily: 'Inter, sans-serif',
      },
      grid: {
        vertLines: { color: 'rgba(30, 41, 59, 0.4)' },
        horzLines: { color: 'rgba(30, 41, 59, 0.4)' },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
        vertLine: { color: '#6366f1', labelBackgroundColor: '#6366f1', style: 3 },
        horzLine: { color: '#6366f1', labelBackgroundColor: '#6366f1', style: 3 },
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
        secondsVisible: false,
        barSpacing: 8,
      },
      rightPriceScale: {
        borderColor: '#1e293b',
        autoScale: true,
        alignLabels: true,
        scaleMargins: { top: 0.1, bottom: 0.1 },
      },
      handleScroll: { mouseWheel: true, pressedMouseMove: true },
      handleScale: { axisPressedMouseMove: true, mouseWheel: true },
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
      priceFormat: {
        type: 'price',
        precision: asset.decimals,
        minMove: 1 / Math.pow(10, asset.decimals),
      },
    });

    chartRef.current = chart;
    seriesRef.current = candlestickSeries;
    setIsReady(true);

    const handleResize = () => {
      if (chartContainerRef.current && chartRef.current) {
        chartRef.current.applyOptions({ 
          width: chartContainerRef.current.clientWidth, 
          height: chartContainerRef.current.clientHeight 
        });
      }
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      chart.remove();
    };
  }, [asset.symbol]);

  useEffect(() => {
    if (seriesRef.current && chartRef.current && candles.length > 0) {
      const formattedData = candles.map(c => ({
        time: (c.time + offsetInSeconds) as Time,
        open: c.open,
        high: c.high,
        low: c.low,
        close: c.close,
      }));

      seriesRef.current.setData(formattedData);

      if (initialLoadRef.current) {
        chartRef.current.timeScale().fitContent();
        initialLoadRef.current = false;
      }
    }
  }, [candles, offsetInSeconds]);

  return (
    <div className="relative w-full h-full bg-[#0f172a]">
        <div ref={chartContainerRef} className="w-full h-full" />

        {loading && (
            <div className="absolute inset-0 flex items-center justify-center bg-slate-950/70 backdrop-blur-sm z-50">
                <div className="flex flex-col items-center gap-3">
                    <div className="w-8 h-8 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Loading Market Data...</span>
                </div>
            </div>
        )}
    </div>
  );
};

export default TradingChart;
